import java.util.Objects;

public class BinarySearchTree<T extends Comparable<T>> {

    private class TreeNode<T> {
        T data;
        TreeNode<T> left;
        TreeNode<T> right;

        TreeNode(T data) {
            this.data = data;
            this.left = null;
            this.right = null;
        }
    }

    /**
     * Esegue una rotazione a destra del nodo.
     * @param node un nodo da ruotare
     * @return un nuovo genitore del {@code node}
     */
    private TreeNode<T> rotateRight(TreeNode<T> node) {
        if (node == null || node.left == null) {
            return node;
        }

        TreeNode<T> newParent = node.left;
        node.left = newParent.right;
        newParent.right = node;

        return newParent;
    }
}

import java.io.File;
import java.net.URL;
import java.util.Vector;

public class ClassPathUtils {

    /**
     * Aggiunge tutti i file jar in una directory al classpath, rappresentato come un Vector di URL.
     */
    @SuppressWarnings("unchecked")
    public static void addToClassPath(Vector<URL> cpV, String dir) {
        File directory = new File(dir);

        // Verifica che la directory esista ed è effettivamente una directory
        if (!directory.exists() || !directory.isDirectory()) {
            return;
        }

        // Ottiene la lista di tutti i file nella directory
        File[] files = directory.listFiles();
        if (files == null) {
            return;
        }

        // Itera su tutti i file
        for (File file : files) {
            // Controlla se il file è un file JAR
            if (file.isFile() && file.getName().toLowerCase().endsWith(".jar")) {
                try {
                    // Converte il file in URL e lo aggiunge al vector
                    URL jarUrl = file.toURI().toURL();
                    if (!cpV.contains(jarUrl)) {
                        cpV.add(jarUrl);
                    }
                } catch (Exception e) {
                    // Ignora eventuali errori di conversione
                    e.printStackTrace();
                }
            }
        }
    }
}

import org.apache.log4j.spi.LoggingEvent;
import java.text.SimpleDateFormat;
import java.util.Date;

public class CustomFormatter {

    /**
     * Produce una stringa formattata come specificato dal modello di conversione.
     */
    public String format(LoggingEvent event) {
        if (event == null) {
            return "";
        }

        StringBuilder formattedMessage = new StringBuilder();

        // Add timestamp
        SimpleDateFormat dateFormat = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss,SSS");
        String timestamp = dateFormat.format(new Date(event.getTimeStamp()));
        formattedMessage.append(timestamp);
        formattedMessage.append(" ");

        // Add log level
        formattedMessage.append("[");
        formattedMessage.append(event.getLevel().toString());
        formattedMessage.append("] ");

        // Add logger name
        formattedMessage.append(event.getLoggerName());
        formattedMessage.append(" - ");

        // Add message
        formattedMessage.append(event.getRenderedMessage());

        // Add throwable info if exists
        String[] throwableInfo = event.getThrowableStrRep();
        if (throwableInfo != null) {
            formattedMessage.append("\n");
            for (String line : throwableInfo) {
                formattedMessage.append(line);
                formattedMessage.append("\n");
            }
        }

        return formattedMessage.toString();
    }
}

