public class RequestWrapper {
    private HttpServletRequest request;

    /**
     * Recupera la lunghezza del contenuto della richiesta.
     * @return La lunghezza del contenuto della richiesta.
     * @since 1.3
     */
    public long contentLength() {
        long length = request.getContentLengthLong();
        if (length < 0) {
            // If content length header not set, try to get actual content length
            try {
                length = request.getInputStream().available();
            } catch (Exception e) {
                length = -1L;
            }
        }
        return length;
    }
}

public class FilenameUtils {
    /**
     * Restituisce l'indice dell'ultimo carattere separatore di directory.
     * <p>
     * Questo metodo gestirà un file sia in formato Unix che Windows.
     * Viene restituita la posizione dell'ultimo slash o backslash.
     * <p>
     * L'output sarà lo stesso indipendentemente dalla macchina su cui il codice viene eseguito.
     *
     * @param filename il nome del file in cui trovare l'ultimo separatore di percorso, null restituisce -1
     * @return l'indice dell'ultimo carattere separatore, oppure -1 se non esiste tale carattere
     */
    public static int indexOfLastSeparator(String filename) {
        if (filename == null) {
            return -1;
        }

        int lastUnixPos = filename.lastIndexOf('/');
        int lastWindowsPos = filename.lastIndexOf('\\');

        return Math.max(lastUnixPos, lastWindowsPos);
    }
}

import java.util.Objects;

public class HeaderParser {

    /**
     * Salta i byte fino alla fine della riga corrente.
     * @param headerPart Le intestazioni che vengono analizzate.
     * @param end Indice dell'ultimo byte che deve ancora essere elaborato.
     * @return Indice della sequenza \r\n, che indica la fine della riga.
     */
    private int parseEndOfLine(String headerPart, int end) {
        Objects.requireNonNull(headerPart);

        int index = end;
        while (index < headerPart.length()) {
            // Cerca la sequenza \r\n che indica fine riga
            if (index + 1 < headerPart.length() && 
                headerPart.charAt(index) == '\r' && 
                headerPart.charAt(index + 1) == '\n') {
                return index;
            }
            index++;
        }

        // Se non trova \r\n ritorna l'ultimo indice valido
        return headerPart.length() - 1;
    }
}

