import org.jgrapht.Graph;
import org.jgrapht.GraphMapping;
import org.jgrapht.graph.AsGraphUnion;
import org.jgrapht.alg.isomorphism.IsomorphicGraphMapping;
import java.util.HashMap;
import java.util.Map;

public class GraphUtils {

    /**
     * Calcola un automorfismo identitario (cioè una mappatura di un grafo in cui ogni vertice si mappa su se stesso).
     * @param graph il grafo di input
     * @param <V> il tipo di vertice del grafo 
     * @param <E> il tipo di arco del grafo
     * @return una mappatura da grafo a grafo
     */
    public static <V,E> IsomorphicGraphMapping<V,E> identity(Graph<V,E> graph) {
        // Create identity mappings for vertices and edges
        Map<V,V> vertexCorrespondence = new HashMap<>();
        Map<E,E> edgeCorrespondence = new HashMap<>();

        // Map each vertex to itself
        for(V vertex : graph.vertexSet()) {
            vertexCorrespondence.put(vertex, vertex);
        }

        // Map each edge to itself 
        for(E edge : graph.edgeSet()) {
            edgeCorrespondence.put(edge, edge);
        }

        return new IsomorphicGraphMapping<>(
            graph, // Graph 1 is the input graph
            graph, // Graph 2 is the same graph
            vertexCorrespondence,
            edgeCorrespondence
        );
    }
}

import java.io.File;
import java.io.IOException;
import java.nio.file.*;
import java.nio.file.attribute.BasicFileAttributes;

public class FileUtils {

    /**
     * Pianifica la cancellazione di un file quando la JVM termina. Se il file è una directory, cancella lei e tutte le sottodirectory.
     * @param file file o directory da cancellare, non deve essere {@code null}
     * @throws NullPointerException se il file è {@code null}
     * @throws IOException in caso di cancellazione non riuscita
     */
    public static void forceDeleteOnExit(File file) throws IOException {
        if (file == null) {
            throw new NullPointerException("File cannot be null");
        }

        if (!file.exists()) {
            return;
        }

        if (file.isDirectory()) {
            // Registra tutti i file e sottodirectory per la cancellazione
            Files.walkFileTree(file.toPath(), new SimpleFileVisitor<Path>() {
                @Override
                public FileVisitResult visitFile(Path file, BasicFileAttributes attrs) {
                    file.toFile().deleteOnExit();
                    return FileVisitResult.CONTINUE;
                }

                @Override
                public FileVisitResult preVisitDirectory(Path dir, BasicFileAttributes attrs) {
                    dir.toFile().deleteOnExit();
                    return FileVisitResult.CONTINUE;
                }
            });
        } else {
            // Se è un file semplice, registra solo quello
            file.deleteOnExit();
        }
    }
}

import javax.swing.SwingUtilities;
import java.util.logging.LogRecord;

public class Logger {
    private LogTable logTable; // Assume LogTable is defined elsewhere

    /**
     * Aggiunge un messaggio di registrazione da visualizzare nella LogTable. 
     * Questo metodo è thread-safe in quanto invia le richieste al SwingThread anziché elaborarle direttamente.
     */
    public void addMessage(final LogRecord lr) {
        if (lr == null) {
            return;
        }

        SwingUtilities.invokeLater(new Runnable() {
            @Override
            public void run() {
                try {
                    logTable.addLogRecord(lr);
                } catch (Exception e) {
                    System.err.println("Error adding log record: " + e.getMessage());
                }
            }
        });
    }
}

import java.util.*;
import org.jgrapht.*;

public class BipartiteGraphGenerator<V,E> implements GraphGenerator<V,E,V> {

    private int n1; // size of first partition
    private int n2; // size of second partition

    public BipartiteGraphGenerator(int n1, int n2) {
        this.n1 = n1;
        this.n2 = n2;
    }

    @Override
    public void generateGraph(Graph<V,E> target, Map<String,V> resultMap) {
        // Create vertices for first partition
        List<V> partition1 = new ArrayList<>();
        for(int i = 0; i < n1; i++) {
            V vertex = target.vertexSupplier().get();
            target.addVertex(vertex);
            partition1.add(vertex);
            if(resultMap != null) {
                resultMap.put("P1_" + i, vertex);
            }
        }

        // Create vertices for second partition  
        List<V> partition2 = new ArrayList<>();
        for(int i = 0; i < n2; i++) {
            V vertex = target.vertexSupplier().get();
            target.addVertex(vertex);
            partition2.add(vertex);
            if(resultMap != null) {
                resultMap.put("P2_" + i, vertex);
            }
        }

        // Add edges between all vertices in partition1 and partition2
        for(V v1 : partition1) {
            for(V v2 : partition2) {
                target.addEdge(v1, v2);
            }
        }
    }
}

import java.util.Arrays;

public class ByteBuffer {
    private byte[] buffer;

    /**
     * Cerca un byte di valore specificato nel <code>buffer</code>, partendo dalla <code>posizione</code> specificata.
     * @param value Il valore da cercare.
     * @param pos   La posizione di partenza per la ricerca.
     * @return La posizione del byte trovato, contando dall'inizio del <code>buffer</code>, oppure <code>-1</code> se non trovato.
     */
    protected int findByte(byte value, int pos) {
        if (buffer == null || pos >= buffer.length) {
            return -1;
        }

        for (int i = pos; i < buffer.length; i++) {
            if (buffer[i] == value) {
                return i;
            }
        }

        return -1;
    }
}

import com.dyuproject.protostuff.LinkedBuffer;
import com.dyuproject.protostuff.Schema;
import com.dyuproject.protostuff.ProtobufOutput;
import java.io.IOException;
import java.io.OutputStream;

public class MessageSerializer {

    /**
     * Serializza il {@code message}, precedendolo con la sua lunghezza, in un {@link OutputStream}.
     * @return la dimensione del messaggio
     */
    public static <T> int writeDelimitedTo(OutputStream out, T message, Schema<T> schema, LinkedBuffer buffer) throws IOException {
        // Create protobuf output using the buffer
        final ProtobufOutput output = new ProtobufOutput(buffer);

        // Serialize the message to get its size
        schema.writeTo(output, message);

        // Get the size of the serialized message
        int size = output.getSize();

        // Write the size as a varint to the output stream
        while ((size & ~0x7F) != 0) {
            out.write((size & 0x7F) | 0x80);
            size >>>= 7;
        }
        out.write(size);

        // Write the actual message
        LinkedBuffer.writeTo(out, buffer);

        // Return the total size of the message
        return output.getSize();
    }
}

