public class SymbolTable {
    private List<String> types;

    public SymbolTable() {
        types = new ArrayList<>();
    }

    /**
     * Aggiunge un tipo nella tabella dei tipi di questa tabella dei simboli. 
     * Non fa nulla se la tabella dei tipi contiene già un tipo simile.
     * @param value un nome di classe interno.
     * @return l'indice di un nuovo tipo o di un tipo già esistente con il valore fornito.
     */
    public int addType(final String value) {
        // Check if type already exists
        int existingIndex = types.indexOf(value);
        if (existingIndex != -1) {
            return existingIndex;
        }

        // Add new type and return its index
        types.add(value);
        return types.size() - 1;
    }
}

import java.lang.reflect.ParameterizedType;
import java.lang.reflect.Type;
import java.lang.reflect.TypeVariable;
import java.util.HashMap;
import java.util.Map;

public class TypeResolver {

    public static Class<?>[] resolveArguments(Type genericType, Class<?> targetType) {
        if (!(genericType instanceof ParameterizedType)) {
            return null;
        }

        ParameterizedType parameterizedType = (ParameterizedType) genericType;
        Type[] actualTypeArguments = parameterizedType.getActualTypeArguments();
        Class<?>[] resolvedTypes = new Class<?>[actualTypeArguments.length];

        // Map to store type variable mappings
        Map<TypeVariable<?>, Type> typeVariableMap = new HashMap<>();

        // Get type variables from target type
        TypeVariable<?>[] typeParameters = targetType.getTypeParameters();

        // Map type variables to actual types
        for (int i = 0; i < actualTypeArguments.length; i++) {
            Type actualType = actualTypeArguments[i];

            if (actualType instanceof Class) {
                resolvedTypes[i] = (Class<?>) actualType;
            } else if (actualType instanceof TypeVariable) {
                TypeVariable<?> typeVar = (TypeVariable<?>) actualType;
                Type resolvedType = typeVariableMap.get(typeVar);

                if (resolvedType instanceof Class) {
                    resolvedTypes[i] = (Class<?>) resolvedType;
                } else {
                    // Cannot resolve type variable
                    return null;
                }
            } else {
                // Cannot handle other types
                return null;
            }
        }

        return resolvedTypes;
    }
}

import java.util.Objects;
import java.util.concurrent.atomic.AtomicReference;

public class MetricsCache<METRICS> {

    private final AtomicReference<METRICS> cache = new AtomicReference<>();

    /**
     * Accetta i dati nella cache e li unisce con il valore esistente. Questo metodo non è thread-safe, si dovrebbe evitare di chiamarlo in concorrenza.
     * @param data da aggiungere potenzialmente.
     */
    @Override
    public void accept(final METRICS data) {
        Objects.requireNonNull(data, "Input data cannot be null");

        METRICS currentValue = cache.get();
        if (currentValue == null) {
            cache.set(data);
        } else {
            // Since we don't know the exact type of METRICS, we assume it has a merge method
            // In a real implementation, you would need to implement the specific merge logic
            try {
                if (currentValue instanceof Mergeable) {
                    ((Mergeable)currentValue).merge(data);
                } else {
                    // Default behavior is to replace the old value
                    cache.set(data);
                }
            } catch (Exception e) {
                // Fallback to simple replacement if merge fails
                cache.set(data);
            }
        }
    }

    // Interface for mergeable objects
    public interface Mergeable<T> {
        void merge(T other);
    }
}

import java.util.Objects;

public class Bucket {
    private Bucket prev;
    private Bucket next;

    /**
     * Inserisce questo bucket nella struttura dati prima del {@code bucket}.
     * @param bucket il bucket, che sarà il successivo a questo bucket.
     */
    void insertBefore(Bucket bucket) {
        Objects.requireNonNull(bucket);

        this.next = bucket;
        this.prev = bucket.prev;

        if (bucket.prev != null) {
            bucket.prev.next = this;
        }

        bucket.prev = this;
    }
}

