import java.io.File;

public class ConfigurationManager {
    /**
     * Crea la directory in cui verrà scritta la lista dei file MRU. La directory "lf5" viene creata 
     * nella directory Documenti e Impostazioni sui computer Windows 2000 e ovunque punti la 
     * variabile user.home su tutte le altre piattaforme.
     */
    public static void createConfigurationDirectory() {
        String userHome = System.getProperty("user.home");
        String configDirPath;

        if (System.getProperty("os.name").toLowerCase().contains("windows")) {
            configDirPath = userHome + File.separator + "Documenti e Impostazioni" + 
                           File.separator + "lf5";
        } else {
            configDirPath = userHome + File.separator + "lf5";
        }

        File configDir = new File(configDirPath);

        if (!configDir.exists()) {
            boolean created = configDir.mkdirs();
            if (!created) {
                throw new RuntimeException("Impossibile creare la directory di configurazione: " + 
                                         configDirPath);
            }
        }
    }
}

import org.objectweb.asm.ClassReader;
import org.objectweb.asm.Attribute;

public class CustomClassReader extends ClassReader {

    public CustomClassReader(byte[] classFile) {
        super(classFile);
    }

    /**
     * Legge un valore long firmato in questo {@link ClassReader}. <i>Questo metodo è destinato alle sottoclassi di {@link Attribute} e normalmente non è necessario per i generatori di classi o adattatori.</i>
     * @param offset l'offset di partenza del valore da leggere in questo {@link ClassReader}.
     * @return il valore letto.
     */
    public long readLong(final int offset) {
        byte[] b = this.b;
        return (((long)b[offset] & 0xFF) << 56)
            | (((long)b[offset + 1] & 0xFF) << 48)
            | (((long)b[offset + 2] & 0xFF) << 40) 
            | (((long)b[offset + 3] & 0xFF) << 32)
            | (((long)b[offset + 4] & 0xFF) << 24)
            | (((long)b[offset + 5] & 0xFF) << 16)
            | (((long)b[offset + 6] & 0xFF) << 8)
            | ((long)b[offset + 7] & 0xFF);
    }
}

import java.util.Arrays;

public class ByteArrayComparator {

    private byte[] internalArray;

    /**
     * Constructor to initialize internal array
     */
    public ByteArrayComparator(byte[] array) {
        this.internalArray = array;
    }

    /**
     * Restituisce true se i contenuti dell'array interno e dell'array fornito corrispondono.
     */
    public boolean equals(final byte[] data, int offset, final int len) {
        if (data == null || offset < 0 || len < 0 || offset + len > data.length) {
            return false;
        }

        if (internalArray.length != len) {
            return false;
        }

        for (int i = 0; i < len; i++) {
            if (internalArray[i] != data[offset + i]) {
                return false;
            }
        }

        return true;
    }
}

