import org.apache.log4j.spi.LoggingEvent;
import java.util.concurrent.ArrayBlockingQueue;

public class LogBuffer {
    private final ArrayBlockingQueue<LoggingEvent> buffer;
    private static final int DEFAULT_BUFFER_SIZE = 1000;

    public LogBuffer() {
        this(DEFAULT_BUFFER_SIZE);
    }

    public LogBuffer(int bufferSize) {
        buffer = new ArrayBlockingQueue<>(bufferSize);
    }

    /**
     * Inserisce un {@link LoggingEvent} nel buffer. Se il buffer è pieno, l'evento viene 
     * <b>silenziosamente scartato</b>. È responsabilità del chiamante assicurarsi che 
     * il buffer abbia spazio libero.
     */
    public void put(LoggingEvent o) {
        if (o != null) {
            buffer.offer(o); // Uses offer() instead of add() to silently discard when full
        }
    }
}

import java.util.ArrayList;
import java.util.List;

public class TimeRangeBuilder {

    // Constant for maximum duration between start and end time
    private static final long FETCH_DATA_DURATION = 24 * 60 * 60 * 1000; // 24 hours in milliseconds

    /**
     * Suddivide gli intervalli di tempo per garantire che l'orario di inizio e l'orario di fine siano inferiori a {@link #FETCH_DATA_DURATION}
     */
    protected List<TimeRange> buildTimeRanges(long start, long end) {
        List<TimeRange> ranges = new ArrayList<>();

        // If total duration is less than max duration, return single range
        if (end - start <= FETCH_DATA_DURATION) {
            ranges.add(new TimeRange(start, end));
            return ranges;
        }

        // Split into multiple ranges of FETCH_DATA_DURATION
        long currentStart = start;
        while (currentStart < end) {
            long currentEnd = Math.min(currentStart + FETCH_DATA_DURATION, end);
            ranges.add(new TimeRange(currentStart, currentEnd));
            currentStart = currentEnd;
        }

        return ranges;
    }

    // Inner class to represent a time range
    protected static class TimeRange {
        private final long start;
        private final long end;

        public TimeRange(long start, long end) {
            this.start = start;
            this.end = end;
        }

        public long getStart() {
            return start;
        }

        public long getEnd() {
            return end;
        }
    }
}

package org.apache.commons.lang3;

/**
 * Utility class for converting between primitive and wrapper arrays.
 */
public class ArrayUtils {

    /**
     * <p>Converte un array di oggetti Byte in primitivi.</p>
     * <p>Questo metodo restituisce <code>null</code> per un array di input <code>null</code>.</p>
     * @param array  un array di <code>Byte</code>, può essere <code>null</code>
     * @return un array di <code>byte</code>, <code>null</code> se l'array di input è nullo
     * @throws NullPointerException se il contenuto dell'array è <code>null</code>
     */
    public static byte[] toPrimitive(final Byte[] array) {
        if (array == null) {
            return null;
        }

        final byte[] result = new byte[array.length];
        for (int i = 0; i < array.length; i++) {
            result[i] = array[i]; // Throws NPE if array[i] is null
        }
        return result;
    }
}

public class TimeCompressor {
    /**
     * Segui il valore di dayStep per riformattare il valore numerico "long" del bucket temporale. Ad esempio, se dayStep == 11, il bucket di tempo riformattato per 20000105 è 20000101, per 20000115 è 20000112, e per 20000123 è 20000123.
     */
    static long compressTimeBucket(long timeBucket, int dayStep) {
        // Convert timeBucket to individual components
        int year = (int)(timeBucket / 10000);
        int month = (int)((timeBucket % 10000) / 100);
        int day = (int)(timeBucket % 100);

        // Calculate compressed day based on dayStep
        int compressedDay;
        if (day <= dayStep) {
            compressedDay = 1;
        } else if (day <= dayStep * 2) {
            compressedDay = dayStep + 1;
        } else {
            compressedDay = day;
        }

        // Reconstruct compressed timeBucket
        return year * 10000L + month * 100L + compressedDay;
    }

    // Test the implementation
    public static void main(String[] args) {
        System.out.println(compressTimeBucket(20000105L, 11)); // Should output 20000101
        System.out.println(compressTimeBucket(20000115L, 11)); // Should output 20000112
        System.out.println(compressTimeBucket(20000123L, 11)); // Should output 20000123
    }
}

import java.nio.charset.StandardCharsets;

public class UTF8Utils {
    /**
     * Calcola la dimensione della stringa utf8 che inizia all'indice specificato {@code index} con la lunghezza specificata {@code length}.
     */
    public static int computeUTF8Size(final CharSequence str, final int index, final int len) {
        int utf8Size = 0;
        final int end = index + len;

        for (int i = index; i < end; i++) {
            char c = str.charAt(i);

            if (c < 0x80) {
                // ASCII character (1 byte)
                utf8Size++;
            } else if (c < 0x800) {
                // 2-byte UTF-8 character
                utf8Size += 2;
            } else if (Character.isSurrogate(c)) {
                // 4-byte UTF-8 character (surrogate pair)
                utf8Size += 4;
                i++; // Skip the low surrogate
            } else {
                // 3-byte UTF-8 character
                utf8Size += 3;
            }
        }

        return utf8Size;
    }
}

