public class StringUtils {
    /**
     * Restituisce {@code true} se la stringa fornita inizia con il prefisso specificato, ignorando le maiuscole, {@code false} altrimenti.
     * @param str la String da controllare
     * @param prefix il prefisso da cercare
     * @return {@code true} se la stringa fornita inizia con il prefisso specificato, ignorando le maiuscole, {@code false} altrimenti.
     * @see java.lang.String#startsWith
     */
    public static boolean startsWithIgnoreCase(String str, String prefix) {
        if (str == null || prefix == null) {
            return false;
        }
        if (prefix.length() > str.length()) {
            return false;
        }
        return str.substring(0, prefix.length()).toLowerCase().equals(prefix.toLowerCase());
    }
}

import java.util.*;

public class Graph<V> {
    // Assuming we have a graph representation with edges stored in a set/list
    private Set<Edge<V>> edges;

    private Set<V> initVisibleVertices() {
        Set<V> visibleVertices = new HashSet<>();

        // Iterate through all edges and add both vertices of each edge
        for (Edge<V> edge : edges) {
            visibleVertices.add(edge.getSource());
            visibleVertices.add(edge.getTarget());
        }

        return visibleVertices;
    }

    // Helper Edge class
    private static class Edge<V> {
        private V source;
        private V target;

        public Edge(V source, V target) {
            this.source = source;
            this.target = target;
        }

        public V getSource() {
            return source;
        }

        public V getTarget() {
            return target;
        }
    }
}

