import java.nio.charset.StandardCharsets;

public class UTF8Writer {
    /**
     * Scrive i byte codificati in utf8 dalla stringa nel {@link LinkedBuffer}.
     */
    public static LinkedBuffer writeUTF8(final CharSequence str, final WriteSession session, final LinkedBuffer lb) {
        if (str == null || str.length() == 0) {
            return lb;
        }

        byte[] utf8Bytes = str.toString().getBytes(StandardCharsets.UTF_8);
        LinkedBuffer currentBuffer = lb;

        int offset = 0;
        while (offset < utf8Bytes.length) {
            int remaining = currentBuffer.buffer.length - currentBuffer.offset;
            int bytesToCopy = Math.min(remaining, utf8Bytes.length - offset);

            System.arraycopy(utf8Bytes, offset, currentBuffer.buffer, currentBuffer.offset, bytesToCopy);
            currentBuffer.offset += bytesToCopy;
            offset += bytesToCopy;

            if (offset < utf8Bytes.length) {
                currentBuffer = new LinkedBuffer(session.nextBufferSize);
                session.tail = currentBuffer;
            }
        }

        return currentBuffer;
    }

    // Supporting class definitions
    public static class LinkedBuffer {
        byte[] buffer;
        int offset;
        LinkedBuffer next;

        public LinkedBuffer(int size) {
            this.buffer = new byte[size];
            this.offset = 0;
        }
    }

    public static class WriteSession {
        LinkedBuffer tail;
        int nextBufferSize;

        public WriteSession(int bufferSize) {
            this.nextBufferSize = bufferSize;
        }
    }
}

import java.util.LinkedList;

public class TreeEdge {
    private TreeEdge prev;
    private TreeEdge next;
    private LinkedList<TreeEdge> edgeList;

    /**
     * Rimuove questo arco da entrambe le liste doppiamente collegate degli archi dell'albero.
     */
    public void removeFromTreeEdgeList() {
        if (prev != null) {
            prev.next = next;
        }

        if (next != null) {
            next.prev = prev;
        }

        if (edgeList != null && edgeList.contains(this)) {
            edgeList.remove(this);
        }

        // Reset references
        prev = null;
        next = null;
        edgeList = null;
    }
}

import java.util.Properties;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class PropertyUtils {

    /**
     * Trova il valore corrispondente a <code>key</code> in <code>props</code>. 
     * Quindi esegui la sostituzione delle variabili sul valore trovato.
     */
    public static String findAndSubst(String key, Properties props) {
        if (key == null || props == null) {
            return null;
        }

        String value = props.getProperty(key);
        if (value == null) {
            return null;
        }

        // Pattern per trovare variabili del tipo ${var}
        Pattern pattern = Pattern.compile("\\$\\{([^}]+)\\}");
        Matcher matcher = pattern.matcher(value);
        StringBuffer result = new StringBuffer();

        while (matcher.find()) {
            String varName = matcher.group(1);
            String replacement = props.getProperty(varName);

            // Se la variabile non è definita, lascia il placeholder originale
            if (replacement == null) {
                replacement = "${" + varName + "}";
            }

            // Escape dei caratteri speciali nella stringa di sostituzione
            replacement = Matcher.quoteReplacement(replacement);
            matcher.appendReplacement(result, replacement);
        }

        matcher.appendTail(result);
        return result.toString();
    }
}

import java.util.Arrays;

public class ToStringBuilder {

    /**
     * <p>Aggiunge al <code>toString</code> i dettagli di un array di <code>int</code>.</p>
     * @param buffer  il <code>StringBuffer</code> da popolare
     * @param fieldName  il nome del campo, tipicamente non utilizzato poiché già aggiunto
     * @param array  l'array da aggiungere al <code>toString</code>, non <code>null</code>
     */
    protected void appendDetail(StringBuffer buffer, String fieldName, int[] array) {
        buffer.append('[');
        for (int i = 0; i < array.length; i++) {
            if (i > 0) {
                buffer.append(',');
            }
            buffer.append(array[i]);
        }
        buffer.append(']');
    }
}

