}

import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.io.InputStream;
import java.util.Iterator;
import java.util.Queue;
import java.util.LinkedList;

public class FileIterator implements Iterator<InputStream> {
    private Queue<File> files;

    public FileIterator() {
        this.files = new LinkedList<>();
    }

    /** 
     * Restituisce il prossimo oggetto {@link java.io.File} oppure {@code null} se non ci sono più file disponibili.
     */
    public InputStream next() throws IOException {
        if (files.isEmpty()) {
            return null;
        }

        File nextFile = files.poll();
        if (nextFile != null && nextFile.exists() && nextFile.isFile()) {
            return new FileInputStream(nextFile);
        }

        return null;
    }

    public void addFile(File file) {
        if (file != null) {
            files.offer(file);
        }
    }

    @Override
    public boolean hasNext() {
        return !files.isEmpty();
    }
}

import java.util.logging.Logger;

public class LoggerUtils {

    /**
     * Controlla se il logger con il nome specificato esiste nella gerarchia. 
     * Se sì, restituisce il suo riferimento, altrimenti restituisce <code>null</code>.
     * @param name Il nome del logger da cercare.
     */
    public Logger exists(String name) {
        if (name == null || name.trim().isEmpty()) {
            return null;
        }

        // Get the logger manager's logger list
        LogManager logManager = LogManager.getLogManager();
        Enumeration<String> loggerNames = logManager.getLoggerNames();

        // Search through existing loggers
        while (loggerNames.hasMoreElements()) {
            String loggerName = loggerNames.nextElement();
            if (loggerName.equals(name)) {
                return logManager.getLogger(name);
            }
        }

        return null;
    }
}

import java.util.HashMap;
import java.util.Map;

public class ConverterRegistry {

    private final Map<Class<?>, Converter> converters = new HashMap<>();

    /**
     * Cerca e restituisce qualsiasi {@link Converter} registrato per la classe di destinazione specificata; 
     * se non esiste un Converter registrato, restituisce <code>null</code>.
     * @param clazz Classe per la quale restituire un Converter registrato
     * @return Il {@link Converter} registrato o <code>null</code> se non trovato
     */
    public Converter lookup(final Class<?> clazz) {
        if (clazz == null) {
            return null;
        }

        // Cerca il converter direttamente associato alla classe
        Converter converter = converters.get(clazz);
        if (converter != null) {
            return converter;
        }

        // Cerca nelle interfacce implementate
        for (Class<?> iface : clazz.getInterfaces()) {
            converter = converters.get(iface);
            if (converter != null) {
                return converter;
            }
        }

        // Cerca nella gerarchia delle superclassi
        Class<?> superClass = clazz.getSuperclass();
        while (superClass != null) {
            converter = converters.get(superClass);
            if (converter != null) {
                return converter;
            }
            superClass = superClass.getSuperclass();
        }

        return null;
    }
}

interface Converter {
    Object convert(Object source);
}

import java.io.IOException;
import java.io.InputStream;

public class VarintReader {
    private final InputStream input;
    private int position = 0;

    public VarintReader(InputStream input) {
        this.input = input;
    }

    /** 
     * Leggi un Varint "raw" dallo stream.
     */
    public long readRawVarint64() throws IOException {
        long result = 0;
        int shift = 0;
        while (shift < 64) {
            final int b = input.read();
            if (b == -1) {
                throw new IOException("Malformed varint - EOF");
            }
            position++;
            result |= (long)(b & 0x7F) << shift;
            if ((b & 0x80) == 0) {
                return result;
            }
            shift += 7;
        }
        throw new IOException("Malformed varint - too long");
    }
}

