import java.util.Stack;

public class FrameStack {
    private Stack<String> stack;

    public FrameStack() {
        stack = new Stack<>();
    }

    /**
     * Rimuove quanti più tipi astratti possibile dallo stack del frame di output come descritto dal descrittore fornito.
     * @param descriptor un tipo o un descrittore di metodo (nel qual caso vengono rimossi i suoi tipi di argomento).
     */
    private void pop(final String descriptor) {
        int index = 0;
        while (index < descriptor.length()) {
            char c = descriptor.charAt(index);

            switch (c) {
                case '(':
                    // Skip opening parenthesis for method descriptor
                    index++;
                    break;

                case ')':
                    // End of arguments for method descriptor
                    return;

                case 'B':
                case 'C': 
                case 'I':
                case 'S':
                case 'Z':
                case 'F':
                    // Pop single slot types
                    if (!stack.isEmpty()) {
                        stack.pop();
                    }
                    index++;
                    break;

                case 'D':
                case 'J':
                    // Pop double slot types
                    if (!stack.isEmpty()) {
                        stack.pop();
                        if (!stack.isEmpty()) {
                            stack.pop();
                        }
                    }
                    index++;
                    break;

                case 'L':
                    // Skip class descriptor until semicolon
                    if (!stack.isEmpty()) {
                        stack.pop();
                    }
                    index = descriptor.indexOf(';', index) + 1;
                    break;

                case '[':
                    // Skip array dimension
                    index++;
                    break;

                default:
                    // Invalid descriptor character
                    throw new IllegalArgumentException("Invalid descriptor: " + descriptor);
            }
        }
    }
}

import java.io.IOException;
import java.io.OutputStream;

public class ByteOutputStream extends OutputStream {

    private byte[] buffer;
    private int position;

    public ByteOutputStream() {
        buffer = new byte[32]; // Initial buffer size
        position = 0;
    }

    @Override
    public void write(final byte b[], final int off, final int len) throws IOException {
        if (b == null) {
            throw new NullPointerException();
        }

        if (off < 0 || len < 0 || off + len > b.length) {
            throw new IndexOutOfBoundsException();
        }

        // Ensure buffer has enough capacity
        ensureCapacity(position + len);

        // Copy bytes from input array to buffer
        System.arraycopy(b, off, buffer, position, len);
        position += len;
    }

    private void ensureCapacity(int minCapacity) {
        if (minCapacity > buffer.length) {
            // Grow buffer by doubling size
            int newCapacity = Math.max(buffer.length * 2, minCapacity);
            byte[] newBuffer = new byte[newCapacity];
            System.arraycopy(buffer, 0, newBuffer, 0, position);
            buffer = newBuffer;
        }
    }

    // Other required OutputStream methods would go here
    @Override
    public void write(int b) throws IOException {
        ensureCapacity(position + 1);
        buffer[position++] = (byte)b;
    }
}

public class ArrayUtils {
    /**
     * Scambia i due elementi agli indici specificati nell'array fornito.
     * @param <V> il tipo di elementi nell'array
     * @param arr l'array
     * @param i l'indice del primo elemento
     * @param j l'indice del secondo elemento
     */
    public static final <V> void swap(V[] arr, int i, int j) {
        V temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }
}

