import java.util.HashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;

public class Graph<V,E> {

    // Maps to store vertex and edge relationships
    private Map<V, Set<E>> sourceVertexToEdgeMap;
    private Map<V, Set<E>> targetVertexToEdgeMap;
    private Map<E, V> edgeToSourceVertexMap;
    private Map<E, V> edgeToTargetVertexMap;

    public Graph() {
        sourceVertexToEdgeMap = new HashMap<>();
        targetVertexToEdgeMap = new HashMap<>();
        edgeToSourceVertexMap = new HashMap<>();
        edgeToTargetVertexMap = new HashMap<>();
    }

    /**
     * Aggiunge un arco all'indice.
     * @param sourceVertex il vertice sorgente
     * @param targetVertex il vertice di destinazione
     * @param e l'arco
     */
    protected void addToIndex(V sourceVertex, V targetVertex, E e) {
        // Add edge to source vertex map
        sourceVertexToEdgeMap.computeIfAbsent(sourceVertex, k -> new HashSet<>()).add(e);

        // Add edge to target vertex map
        targetVertexToEdgeMap.computeIfAbsent(targetVertex, k -> new HashSet<>()).add(e);

        // Map edge to its source and target vertices
        edgeToSourceVertexMap.put(e, sourceVertex);
        edgeToTargetVertexMap.put(e, targetVertex);
    }
}

import java.io.File;

public class ClassPathUtils {

    /**
     * Restituisce il percorso delle classi dell'istanza JVM corrente come un array di oggetti {@link File}.
     */
    private static File[] classPath() {
        String classPath = System.getProperty("java.class.path");
        String pathSeparator = System.getProperty("path.separator");
        String[] paths = classPath.split(pathSeparator);

        File[] files = new File[paths.length];
        for (int i = 0; i < paths.length; i++) {
            files[i] = new File(paths[i]);
        }

        return files;
    }
}

public class ArrayUtils {
    /**
     * Questo metodo crea una copia dell'array fornito e garantisce che tutte le stringhe 
     * nel nuovo array creato contengano solo lettere minuscole.
     * Utilizzare questo metodo per copiare array di stringhe significa che le modifiche 
     * all'array src non modificano l'array dst.
     *
     * @param src array sorgente da copiare
     * @return nuovo array con stringhe in minuscolo
     */
    private static String[] copyStrings(final String[] src) {
        if (src == null) {
            return null;
        }

        String[] dst = new String[src.length];
        for (int i = 0; i < src.length; i++) {
            if (src[i] != null) {
                dst[i] = src[i].toLowerCase();
            }
        }
        return dst;
    }
}

import java.awt.geom.Point2D;
import javafx.util.Pair;

public class BoxSplitter {

    public static class Box2D {
        private Point2D topLeft;
        private double width;
        private double height;

        public Box2D(Point2D topLeft, double width, double height) {
            this.topLeft = topLeft;
            this.width = width;
            this.height = height;
        }

        public Point2D getTopLeft() {
            return topLeft;
        }

        public double getWidth() {
            return width;
        }

        public double getHeight() {
            return height;
        }
    }

    /** 
     * Divide una "Box2D" lungo l'asse x in due "Box2D" uguali.
     * @param box la scatola da dividere
     * @return una coppia con le due scatole risultanti
     */
    public static Pair<Box2D,Box2D> splitAlongXAxis(Box2D box) {
        // Get original box properties
        Point2D originalTopLeft = box.getTopLeft();
        double originalWidth = box.getWidth();
        double originalHeight = box.getHeight();

        // Calculate half width for the split
        double halfWidth = originalWidth / 2;

        // Create left box with original top-left point
        Box2D leftBox = new Box2D(originalTopLeft, halfWidth, originalHeight);

        // Create right box with new top-left point shifted right by halfWidth
        Point2D rightBoxTopLeft = new Point2D.Double(
            originalTopLeft.getX() + halfWidth,
            originalTopLeft.getY()
        );
        Box2D rightBox = new Box2D(rightBoxTopLeft, halfWidth, originalHeight);

        return new Pair<>(leftBox, rightBox);
    }
}

import java.util.Arrays;

public class ByteVector {
    private byte[] data;
    private int capacity;
    private int size;

    /**
     * Espande questo vettore di byte in modo che possa ricevere 'size' byte aggiuntivi.
     * @param size numero di byte aggiuntivi che questo vettore di byte dovrebbe essere in grado di ricevere.
     */
    private void enlarge(final int size) {
        if (size <= 0) {
            return;
        }

        int newCapacity = this.capacity + size;
        byte[] newData = Arrays.copyOf(this.data, newCapacity);

        this.data = newData;
        this.capacity = newCapacity;
    }
}

import org.apache.log4j.Appender;
import java.util.Enumeration;

public class AppenderManager {
    private Enumeration<Appender> appenders;

    /**
     * Restituisce <code>true</code> se l'appender specificato è presente nell'elenco degli appender allegati, <code>false</code> altrimenti.
     * @since 1.2
     */
    public boolean isAttached(Appender appender) {
        if (appender == null) {
            return false;
        }

        while (appenders != null && appenders.hasMoreElements()) {
            Appender currentAppender = appenders.nextElement();
            if (currentAppender == appender) {
                return true;
            }
        }
        return false;
    }
}

import java.util.Comparator;

public class DoubleComparator implements Comparator<Double> {

    /**
     * Confronta due valori in virgola mobile. Restituisce 0 se sono uguali, -1 se {@literal o1 < o2}, 1 altrimenti
     * @param o1 il primo valore
     * @param o2 il secondo valore
     * @return 0 se sono uguali, -1 se {@literal o1 < o2}, 1 altrimenti
     */
    @Override
    public int compare(Double o1, Double o2) {
        if (o1.equals(o2)) {
            return 0;
        }
        return o1 < o2 ? -1 : 1;
    }
}

