import java.beans.Introspector;

public class StringUtils {
    /**
     * Inverso di Introspector.decapitalize
     */
    public static String capitalize(String name) {
        if (name == null || name.length() == 0) {
            return name;
        }
        if (name.length() > 1 && Character.isUpperCase(name.charAt(1)) &&
                Character.isLowerCase(name.charAt(0))) {
            return name;
        }
        char chars[] = name.toCharArray();
        chars[0] = Character.toUpperCase(chars[0]);
        return new String(chars);
    }
}

import java.io.DataOutput;
import java.io.IOException;

public class BufferWriter {
    /**
     * Scrive il contenuto del {@link LinkedBuffer} nel {@link DataOutput}.
     * @return la dimensione totale del contenuto del buffer.
     */
    public static int writeTo(final DataOutput out, LinkedBuffer node) throws IOException {
        if (out == null || node == null) {
            return 0;
        }

        int totalSize = 0;
        LinkedBuffer current = node;

        while (current != null) {
            byte[] buffer = current.getBuffer();
            int offset = current.getOffset();
            int size = current.getSize();

            if (buffer != null && size > 0) {
                out.write(buffer, offset, size);
                totalSize += size;
            }

            current = current.getNext();
        }

        return totalSize;
    }
}

class LinkedBuffer {
    private byte[] buffer;
    private int offset;
    private int size;
    private LinkedBuffer next;

    public byte[] getBuffer() {
        return buffer;
    }

    public int getOffset() {
        return offset;
    }

    public int getSize() {
        return size;
    }

    public LinkedBuffer getNext() {
        return next;
    }
}

public class BooleanUtils {
    /**
     * <p>Controlla se un valore <code>Boolean</code> è <i>non</i> <code>true</code>, 
     * gestendo <code>null</code> restituendo <code>true</code>.</p>
     *
     * <pre>
     * BooleanUtils.isNotTrue(Boolean.TRUE)  = false
     * BooleanUtils.isNotTrue(Boolean.FALSE) = true 
     * BooleanUtils.isNotTrue(null)          = true
     * </pre>
     *
     * @param bool  il booleano da controllare, null restituisce <code>true</code>
     * @return <code>true</code> se l'input è null o false
     * @since 2.3
     */
    public static boolean isNotTrue(Boolean bool) {
        return !Boolean.TRUE.equals(bool);
    }
}

import java.util.NoSuchElementException;

public class Queue<E> {
    private Node<E> front;
    private Node<E> rear;
    private int size;

    private static class Node<E> {
        E element;
        Node<E> next;

        Node(E element) {
            this.element = element;
            this.next = null;
        }
    }

    /**
     * Restituisce una rappresentazione testuale della coda.
     * @return una rappresentazione testuale della coda.
     */
    public String toString() {
        if (size == 0) {
            return "[]";
        }

        StringBuilder sb = new StringBuilder();
        sb.append("[");

        Node<E> current = front;
        while (current != null) {
            sb.append(current.element);
            if (current.next != null) {
                sb.append(", ");
            }
            current = current.next;
        }

        sb.append("]");
        return sb.toString();
    }
}

import java.util.function.Supplier;

public class StringSupplierCreator {

    /**
     * Crea un fornitore di stringhe che restituisce stringhe uniche. Le stringhe restituite sono semplicemente interi che partono da start.
     * @param start da dove iniziare la sequenza
     * @return un fornitore di stringhe
     */
    @SuppressWarnings("unchecked")
    public static Supplier<String> createStringSupplier(int start) {
        final int[] counter = {start};
        return () -> String.valueOf(counter[0]++);
    }
}

import org.apache.log4j.spi.LoggingEvent;
import java.text.SimpleDateFormat;
import java.util.Date;

public class LogFormatter {

    private static final SimpleDateFormat DATE_FORMAT = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss,SSS");

    /**
     * Formatta un evento di logging per un writer.
     * @param event evento di logging da formattare.
     */
    public String format(final LoggingEvent event) {
        if (event == null) {
            return "";
        }

        StringBuilder sb = new StringBuilder();

        // Add timestamp
        Date timestamp = new Date(event.getTimeStamp());
        sb.append(DATE_FORMAT.format(timestamp));
        sb.append(" ");

        // Add log level
        sb.append("[").append(event.getLevel().toString()).append("] ");

        // Add logger name
        sb.append(event.getLoggerName());
        sb.append(" - ");

        // Add message
        sb.append(event.getRenderedMessage());

        // Add throwable if exists
        String[] throwableStrRep = event.getThrowableStrRep();
        if (throwableStrRep != null) {
            sb.append("\n");
            for (String line : throwableStrRep) {
                sb.append(line).append("\n");
            }
        }

        // Add new line
        sb.append("\n");

        return sb.toString();
    }
}

package org.apache.commons.lang3;

/**
 * Utility class for converting between primitive and wrapper arrays
 */
public class ArrayUtils {

    /**
     * <p>Converte un array di oggetti Double in primitivi.</p>
     * <p>Questo metodo restituisce <code>null</code> per un array di input <code>null</code>.</p>
     * @param array  un array di <code>Double</code>, può essere <code>null</code>
     * @return un array di <code>double</code>, <code>null</code> se l'array di input è nullo
     * @throws NullPointerException se il contenuto dell'array è <code>null</code>
     */
    public static double[] toPrimitive(final Double[] array) {
        if (array == null) {
            return null;
        }

        final double[] result = new double[array.length];
        for (int i = 0; i < array.length; i++) {
            result[i] = array[i].doubleValue();
        }
        return result;
    }
}

