import java.lang.Character;
import java.lang.Class;
import java.lang.Object;
import java.lang.String;

public class CharacterConverter {

    @Override
    protected Object convertToType(final Class<?> type, final Object value) throws Exception {
        if (value == null) {
            return null;
        }

        if (value instanceof Character) {
            return value;
        }

        if (value instanceof String) {
            String str = (String) value;
            if (str.length() == 0) {
                throw new Exception("Cannot convert empty String to Character");
            }
            return Character.valueOf(str.charAt(0));
        }

        if (value instanceof Number) {
            int num = ((Number) value).intValue();
            return Character.valueOf((char) num);
        }

        throw new Exception("Cannot convert " + value.getClass().getName() + " to Character");
    }
}

import java.util.List;

public class StringUtils {

    /**
     * Controllo non sensibile al maiuscolo/minuscolo se la Stringa contiene uno qualsiasi dei caratteri nel set di stringhe fornito.
     */
    public static boolean containsAnyIgnoreCase(String str, List<String> searchStrArray) {
        if (str == null || searchStrArray == null) {
            return false;
        }

        String lowerStr = str.toLowerCase();

        for (String searchStr : searchStrArray) {
            if (searchStr != null && lowerStr.contains(searchStr.toLowerCase())) {
                return true;
            }
        }

        return false;
    }
}

public class HashUtils {
    public static int nextPrime(int desiredCapacity) {
        if (desiredCapacity <= 2) {
            return 2;
        }

        int num = desiredCapacity;
        if (num % 2 == 0) {
            num++; // Start with odd number
        }

        while (!isPrime(num)) {
            num += 2;
        }

        return num;
    }

    private static boolean isPrime(int n) {
        if (n <= 1) return false;
        if (n == 2) return true;
        if (n % 2 == 0) return false;

        int sqrt = (int) Math.sqrt(n);
        for (int i = 3; i <= sqrt; i += 2) {
            if (n % i == 0) {
                return false;
            }
        }
        return true;
    }
}

package org.apache.commons.lang3;

public class CharUtils {
    /**
     * <p>Converte il Character in un char gestendo <code>null</code>.</p>
     * <pre>
     * CharUtils.toChar(null, 'X') = 'X'
     * CharUtils.toChar(' ', 'X')  = ' '
     * CharUtils.toChar('A', 'X')  = 'A'
     * </pre>
     *
     * @param ch  il carattere da convertire
     * @param defaultValue  il valore da utilizzare se il Character è null
     * @return il valore char del Character o il valore predefinito se null
     */
    public static char toChar(final Character ch, final char defaultValue) {
        if (ch == null) {
            return defaultValue;
        }
        return ch.charValue();
    }
}

import java.util.Collection;

public class CollectionUtils {
    /**
     * Restituisce il primo elemento in '<code>candidates</code>' che è contenuto in '<code>source</code>'. 
     * Se nessun elemento in '<code>candidates</code>' è presente in '<code>source</code>', restituisce <code>null</code>. 
     * L'ordine di iterazione è specifico dell'implementazione di {@link Collection}.
     * @param source la Collection sorgente
     * @param candidates i candidati da cercare
     * @return il primo oggetto presente, oppure <code>null</code> se non trovato
     */
    public static Object findFirstMatch(Collection source, Collection candidates) {
        if (source == null || candidates == null) {
            return null;
        }

        for (Object candidate : candidates) {
            if (source.contains(candidate)) {
                return candidate;
            }
        }

        return null;
    }
}

public class StringUtils {
    /**
     * Rimuove gli spazi bianchi finali dalla Stringa fornita.
     * @param str la Stringa da controllare
     * @return la Stringa senza spazi bianchi finali
     * @see java.lang.Character#isWhitespace
     */
    public static String trimTrailingWhitespace(String str) {
        if (str == null) {
            return null;
        }

        int len = str.length();
        while (len > 0 && Character.isWhitespace(str.charAt(len - 1))) {
            len--;
        }

        return str.substring(0, len);
    }
}

import java.io.File;
import java.io.IOException;
import java.util.logging.Logger;
import java.util.logging.Level;

public class ConfigurationManager {
    private static final Logger LOGGER = Logger.getLogger(ConfigurationManager.class.getName());
    private static final String DEFAULT_DEPLOY_PATH = "/opt/deploy";
    private String deployPath;

    /**
     * inizializza la configurazione, ad esempio controlla il percorso di distribuzione
     */
    public void init() {
        try {
            // Check if default deploy path exists
            File deployDir = new File(DEFAULT_DEPLOY_PATH);

            if (!deployDir.exists()) {
                boolean created = deployDir.mkdirs();
                if (created) {
                    LOGGER.info("Created default deployment directory: " + DEFAULT_DEPLOY_PATH);
                } else {
                    LOGGER.warning("Failed to create deployment directory");
                }
            }

            // Verify directory is writable
            if (deployDir.canWrite()) {
                this.deployPath = DEFAULT_DEPLOY_PATH;
                LOGGER.info("Deployment path initialized to: " + this.deployPath);
            } else {
                LOGGER.severe("Deployment directory is not writable");
                throw new IOException("Deployment directory is not writable");
            }

        } catch (SecurityException e) {
            LOGGER.log(Level.SEVERE, "Security exception while initializing configuration", e);
            throw e;
        } catch (IOException e) {
            LOGGER.log(Level.SEVERE, "IO exception while initializing configuration", e);
            throw new RuntimeException("Failed to initialize configuration", e);
        }
    }
}

import java.io.IOException;
import java.io.DataInputStream;

public class DataReader {
    private DataInputStream in;

    public DataReader(DataInputStream in) {
        this.in = in;
    }

    /**
     * Leggi un valore di campo {@code string} dallo stream.
     */
    @Override
    public String readString() throws IOException {
        // Read the string length first
        int length = in.readInt();

        if (length < 0) {
            return null;
        }

        // Create byte array to hold string data
        byte[] bytes = new byte[length];

        // Read the string bytes
        in.readFully(bytes);

        // Convert bytes to string using UTF-8 encoding
        return new String(bytes, "UTF-8");
    }
}

public class CharacterUtils {
    /**
     * Interpreta un carattere come una cifra (in qualsiasi base fino a 36) e restituisce il valore numerico. 
     * Questo è simile a {@code Character.digit()} ma non accettiamo cifre non-ASCII.
     */
    private static int digitValue(final char c) {
        if (c >= '0' && c <= '9') {
            return c - '0';
        }
        if (c >= 'a' && c <= 'z') {
            return c - 'a' + 10;
        }
        if (c >= 'A' && c <= 'Z') {
            return c - 'A' + 10;
        }
        return -1;
    }
}

import java.util.HashMap;
import java.util.Map;
import javax.json.JsonObject;

public class ContentBuilder {

    /**
     * Costruisci il contenuto, se ha "ATS", imposta l'"ATS"
     */
    private Map<String,Object> buildContent(JsonObject jsonObject) {
        Map<String,Object> content = new HashMap<>();

        if (jsonObject != null) {
            // Check if jsonObject contains "ATS" key
            if (jsonObject.containsKey("ATS")) {
                content.put("ATS", jsonObject.getString("ATS"));
            }

            // Add all other key-value pairs from jsonObject to content map
            for (String key : jsonObject.keySet()) {
                if (!key.equals("ATS")) {
                    Object value = jsonObject.get(key);
                    content.put(key, value); 
                }
            }
        }

        return content;
    }
}

import org.atmosphere.cpr.AtmosphereFramework;
import org.atmosphere.cpr.AtmosphereHandler;
import org.atmosphere.cpr.AtmosphereConfig;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

public class AtmosphereFrameworkImpl extends AtmosphereFramework {

    private final Map<String, AtmosphereHandler> handlers = new ConcurrentHashMap<>();

    /** 
     * Rimuove un {@link AtmosphereHandler}.
     * @param mapping il mapping utilizzato quando si invoca {@link #addAtmosphereHandler(String,AtmosphereHandler)};
     * @return true se rimosso
     */
    public AtmosphereFramework removeAtmosphereHandler(String mapping) {
        if (mapping == null || mapping.isEmpty()) {
            return this;
        }

        // Normalize mapping
        String normalizedMapping = mapping.startsWith("/") ? mapping : "/" + mapping;

        // Remove handler if exists
        AtmosphereHandler removed = handlers.remove(normalizedMapping);

        if (removed != null) {
            // Clean up any resources associated with the handler
            removed.destroy();

            // Update framework configuration
            AtmosphereConfig config = getAtmosphereConfig();
            if (config != null) {
                config.properties().remove(normalizedMapping);
            }
        }

        return this;
    }
}

import java.util.Arrays;

public class ByteArrayOutputStream {
    private byte[] buffer;
    private int count;
    private static final int MAX_ARRAY_SIZE = Integer.MAX_VALUE - 8;

    public ByteArrayOutputStream() {
        this(32); // Default initial size
    }

    public ByteArrayOutputStream(int size) {
        if (size < 0) {
            throw new IllegalArgumentException("Negative initial size: " + size);
        }
        buffer = new byte[size];
    }

    /**
     * Restituisce un singolo array di byte contenente tutti i contenuti scritti nel/i buffer.
     */
    public final byte[] toByteArray() {
        return Arrays.copyOf(buffer, count);
    }

    // Helper method to ensure capacity
    private void ensureCapacity(int minCapacity) {
        if (minCapacity - buffer.length > 0) {
            int oldCapacity = buffer.length;
            int newCapacity = oldCapacity << 1;

            if (newCapacity - minCapacity < 0) {
                newCapacity = minCapacity;
            }

            if (newCapacity - MAX_ARRAY_SIZE > 0) {
                newCapacity = hugeCapacity(minCapacity);
            }

            buffer = Arrays.copyOf(buffer, newCapacity);
        }
    }

    private static int hugeCapacity(int minCapacity) {
        if (minCapacity < 0) {
            throw new OutOfMemoryError();
        }
        return (minCapacity > MAX_ARRAY_SIZE) ? Integer.MAX_VALUE : MAX_ARRAY_SIZE;
    }
}

import java.util.HashMap;
import java.util.Map;

public class StringUtils {

    private static final Map<String, String> JAVA_ESCAPES = new HashMap<>();
    static {
        JAVA_ESCAPES.put("\\t", "\t");
        JAVA_ESCAPES.put("\\b", "\b"); 
        JAVA_ESCAPES.put("\\n", "\n");
        JAVA_ESCAPES.put("\\r", "\r");
        JAVA_ESCAPES.put("\\f", "\f");
        JAVA_ESCAPES.put("\\'", "'");
        JAVA_ESCAPES.put("\\\"", "\"");
        JAVA_ESCAPES.put("\\\\", "\\");
    }

    /** 
     * <p>Rimuove l'escape da qualsiasi letterale Java trovato nella <code>String</code>. Ad esempio, trasformerà una sequenza di <code>'\'</code> e <code>'n'</code> in un carattere di nuova linea, a meno che il <code>'\'</code> non sia preceduto da un altro <code>'\'</code>.</p>
     * @param str la <code>String</code> da desescapare, può essere null
     * @return una nuova <code>String</code> desescapata, <code>null</code> se l'input è una stringa null
     */
    public static String unescapeJava(String str) throws Exception {
        if (str == null) {
            return null;
        }

        StringBuilder result = new StringBuilder(str.length());

        for (int i = 0; i < str.length(); i++) {
            char ch = str.charAt(i);

            if (ch == '\\' && i + 1 < str.length()) {
                // Check for escaped sequences
                String escape = str.substring(i, Math.min(i + 2, str.length()));

                if (JAVA_ESCAPES.containsKey(escape)) {
                    result.append(JAVA_ESCAPES.get(escape));
                    i++; // Skip next character as it's part of escape sequence
                } else if (escape.charAt(1) == 'u' && i + 5 < str.length()) {
                    // Handle Unicode escape sequences
                    String hex = str.substring(i + 2, i + 6);
                    try {
                        result.append((char) Integer.parseInt(hex, 16));
                        i += 5; // Skip the unicode sequence
                    } catch (NumberFormatException e) {
                        throw new Exception("Invalid Unicode escape sequence: \\u" + hex);
                    }
                } else {
                    // Not a recognized escape sequence, keep the backslash
                    result.append(ch);
                }
            } else {
                result.append(ch);
            }
        }

        return result.toString();
    }
}

import java.nio.charset.Charset;
import java.util.HashMap;
import java.util.Map;

public class CharsetConverter {

    private static final Map<String, String> MIME_TO_JAVA_CHARSET = new HashMap<>();

    static {
        MIME_TO_JAVA_CHARSET.put("ISO-8859-1", "ISO-8859-1");
        MIME_TO_JAVA_CHARSET.put("ISO8859_1", "ISO-8859-1");
        MIME_TO_JAVA_CHARSET.put("ISO-8859-2", "ISO-8859-2"); 
        MIME_TO_JAVA_CHARSET.put("ISO8859_2", "ISO-8859-2");
        MIME_TO_JAVA_CHARSET.put("UTF-8", "UTF-8");
        MIME_TO_JAVA_CHARSET.put("UTF8", "UTF-8");
        MIME_TO_JAVA_CHARSET.put("US-ASCII", "US-ASCII");
        MIME_TO_JAVA_CHARSET.put("ASCII", "US-ASCII");
        MIME_TO_JAVA_CHARSET.put("windows-1252", "windows-1252");
        MIME_TO_JAVA_CHARSET.put("CP1252", "windows-1252");
    }

    private static String javaCharset(String charset) {
        if (charset == null || charset.trim().isEmpty()) {
            return Charset.defaultCharset().name();
        }

        String normalized = charset.trim().toUpperCase();
        String javaCharset = MIME_TO_JAVA_CHARSET.get(normalized);

        if (javaCharset != null) {
            return javaCharset;
        }

        try {
            // Verify if the charset is valid by attempting to get an instance
            Charset.forName(charset);
            return charset;
        } catch (Exception e) {
            // If charset is not recognized, return default charset
            return Charset.defaultCharset().name();
        }
    }
}

public class StringQuoter {
    /**
     * Trasforma l'oggetto fornito in una Stringa con virgolette singole se è una Stringa;
     * altrimenti, mantiene l'oggetto così com'è.
     * @param obj l'oggetto di input (ad esempio, "myString")
     * @return la Stringa quotata (ad esempio, "'myString'"), oppure l'oggetto di input così com'è se non è una Stringa
     */
    public static Object quoteIfString(Object obj) {
        if (obj instanceof String) {
            return "'" + obj + "'";
        }
        return obj;
    }
}

import java.util.NoSuchElementException;

public class LinkedList<E> {
    private class ListNode<E> {
        private E data;
        private ListNode<E> next;
        private ListNode<E> prev;

        public ListNode(E data) {
            this.data = data;
            this.next = null;
            this.prev = null;
        }
    }

    private ListNode<E> current;

    /**
     * Returns the previous node in the linked list
     * @return The previous ListNode
     * @throws NoSuchElementException if there is no previous node
     */
    @Override
    public ListNode<E> previousNode() {
        if (current == null || current.prev == null) {
            throw new NoSuchElementException("No previous node exists");
        }
        current = current.prev;
        return current;
    }
}

import org.objectweb.asm.ClassReader;
import org.objectweb.asm.Attribute;

public class CustomClassReader extends ClassReader {

    public CustomClassReader(byte[] classFile) {
        super(classFile);
    }

    /**
     * Legge un valore short firmato in questo {@link ClassReader}. <i>Questo metodo è destinato 
     * alle sottoclassi di {@link Attribute} e normalmente non è necessario per i generatori 
     * di classi o gli adattatori.</i>
     * @param offset l'offset di partenza del valore da leggere in questo {@link ClassReader}.
     * @return il valore letto.
     */
    public short readShort(final int offset) {
        byte[] classFileBuffer = this.b;
        return (short)((classFileBuffer[offset] & 0xFF) << 8 | 
                      (classFileBuffer[offset + 1] & 0xFF));
    }
}

import java.lang.reflect.Array;

public class ArrayUtils {

    /**
     * Restituisce una copia dell'array fornito di dimensione 1 maggiore rispetto all'argomento. 
     * L'ultimo valore dell'array viene lasciato al valore predefinito.
     * @param array L'array da copiare, non deve essere <code>null</code>.
     * @param newArrayComponentType Se <code>array</code> è <code>null</code>, crea un array di dimensione 1 di questo tipo.
     * @return Una nuova copia dell'array di dimensione 1 maggiore rispetto all'input.
     */
    private static Object copyArrayGrow1(final Object array, final Class<?> newArrayComponentType) {
        if (array != null) {
            int arrayLength = Array.getLength(array);
            Object newArray = Array.newInstance(array.getClass().getComponentType(), arrayLength + 1);
            System.arraycopy(array, 0, newArray, 0, arrayLength);
            return newArray;
        }
        return Array.newInstance(newArrayComponentType, 1);
    }
}

public class BinaryLogCalculator {
    /**
     * Calcola floor(log_2(n)) + 1
     * Calculates floor(log_2(n)) + 1 by counting the number of bits needed to represent n
     */
    private int computeBinaryLog(int n) {
        if (n <= 0) {
            throw new IllegalArgumentException("Input must be positive");
        }

        // Count number of bits needed to represent n
        return 32 - Integer.numberOfLeadingZeros(n);
    }
}

import java.util.HashSet;
import java.util.Set;

public class SetOperations<V> {

    /**
     * Metodo efficiente per calcolare l'intersezione tra due insiemi
     * @param set1 insieme $1$
     * @param set2 insieme $2$ 
     * @return intersezione dell'insieme $1$ e $2$
     */
    private Set<V> intersection(Set<V> set1, Set<V> set2) {
        // Create new set for result
        Set<V> result = new HashSet<>();

        // Get smaller set to iterate over for better performance
        Set<V> smaller = set1.size() < set2.size() ? set1 : set2;
        Set<V> larger = set1.size() < set2.size() ? set2 : set1;

        // Add elements that exist in both sets
        for (V element : smaller) {
            if (larger.contains(element)) {
                result.add(element);
            }
        }

        return result;
    }
}

