import java.util.ArrayList;
import java.util.List;

public class CategoryTree {
    private CategoryNode root;

    protected class CategoryNode {
        private boolean active;
        private List<CategoryNode> children;

        public CategoryNode() {
            this.active = false;
            this.children = new ArrayList<>();
        }

        public boolean isActive() {
            return active;
        }

        public List<CategoryNode> getChildren() {
            return children;
        }
    }

    protected int removeUnusedNodes() {
        if (root == null) {
            return 0;
        }
        return removeUnusedNodesRecursive(root);
    }

    private int removeUnusedNodesRecursive(CategoryNode node) {
        int removedCount = 0;

        // Create a list to store children that need to be removed
        List<CategoryNode> nodesToRemove = new ArrayList<>();

        // Recursively process all children
        for (CategoryNode child : node.getChildren()) {
            removedCount += removeUnusedNodesRecursive(child);

            // If child is inactive and has no children, mark it for removal
            if (!child.isActive() && child.getChildren().isEmpty()) {
                nodesToRemove.add(child);
                removedCount++;
            }
        }

        // Remove marked nodes from children list
        node.getChildren().removeAll(nodesToRemove);

        return removedCount;
    }
}

import org.objectweb.asm.Label;

public class BytecodeReader {

    /**
     * Restituisce l'etichetta corrispondente all'offset di bytecode fornito. L'implementazione predefinita di questo metodo crea un'etichetta per l'offset dato se non è già stata creata.
     * @param bytecodeOffset un offset di bytecode in un metodo.
     * @param labels le etichette già create, indicizzate per il loro offset. Se un'etichetta esiste già per bytecodeOffset, questo metodo non deve crearne una nuova. Altrimenti, deve memorizzare la nuova etichetta in questo array.
     * @return un'etichetta non nulla, che deve essere uguale a labels[bytecodeOffset].
     */
    protected Label readLabel(final int bytecodeOffset, final Label[] labels) {
        Label label = labels[bytecodeOffset];
        if (label == null) {
            label = new Label();
            labels[bytecodeOffset] = label;
        }
        return label;
    }
}

public class BooleanUtils {
    /**
     * Se <code>value</code> è "true", viene restituito <code>true</code>. 
     * Se <code>value</code> è "false", viene restituito <code>false</code>. 
     * Altrimenti, viene restituito <code>default</code>.
     * Non importa se <code>value</code> è maiuscolo o minuscolo.
     */
    public static boolean toBoolean(String value, boolean dEfault) {
        if (value == null) {
            return dEfault;
        }

        String lowercaseValue = value.toLowerCase();

        if (lowercaseValue.equals("true")) {
            return true;
        }

        if (lowercaseValue.equals("false")) {
            return false;
        }

        return dEfault;
    }
}

public class StringUtils {
    /**
     * Rimuove gli spazi bianchi iniziali dalla Stringa fornita.
     * @param str la Stringa da controllare
     * @return la Stringa senza spazi bianchi iniziali
     * @see java.lang.Character#isWhitespace
     */
    public static String trimLeadingWhitespace(String str) {
        if (str == null) {
            return null;
        }

        int len = str.length();
        int start = 0;

        while (start < len && Character.isWhitespace(str.charAt(start))) {
            start++;
        }

        return str.substring(start);
    }
}

import java.io.ByteArrayInputStream;
import java.io.DataInputStream;
import java.io.IOException;

public class ClassFileReader {
    private byte[] classFileBuffer;
    private int[] cpInfoOffsets;

    final String readUtf(final int constantPoolEntryIndex, final char[] charBuffer) {
        int offset = cpInfoOffsets[constantPoolEntryIndex];
        int utfLength = readUnsignedShort(offset);
        offset += 2;

        int charLength = 0;
        int currentOffset = offset;
        int endOffset = offset + utfLength;

        while (currentOffset < endOffset) {
            int currentByte = classFileBuffer[currentOffset++] & 0xFF;
            if ((currentByte & 0x80) == 0) {
                charBuffer[charLength++] = (char) currentByte;
            } else if ((currentByte & 0xE0) == 0xC0) {
                charBuffer[charLength++] = (char) (((currentByte & 0x1F) << 6) 
                    + (classFileBuffer[currentOffset++] & 0x3F));
            } else {
                charBuffer[charLength++] = (char) (((currentByte & 0xF) << 12)
                    + ((classFileBuffer[currentOffset++] & 0x3F) << 6) 
                    + (classFileBuffer[currentOffset++] & 0x3F));
            }
        }

        return new String(charBuffer, 0, charLength);
    }

    private int readUnsignedShort(final int offset) {
        byte[] classFileBuffer = this.classFileBuffer;
        return ((classFileBuffer[offset] & 0xFF) << 8) 
            | (classFileBuffer[offset + 1] & 0xFF);
    }
}

public class HexDecoder {
    /**
     * Funzione di supporto per decodificare metà di un numero esadecimale da una stringa.
     * @param c Il carattere ASCII del numero esadecimale da decodificare. Deve essere compreso nell'intervallo {@code [0-9a-fA-F]}.
     * @return Il valore esadecimale rappresentato dal carattere ASCII fornito, oppure {@link Character#MAX_VALUE} se il carattere non è valido.
     */
    private static char decodeHexNibble(final char c) {
        // Per cifre da 0-9
        if (c >= '0' && c <= '9') {
            return (char)(c - '0');
        }

        // Per lettere minuscole a-f
        if (c >= 'a' && c <= 'f') {
            return (char)(c - 'a' + 10);
        }

        // Per lettere maiuscole A-F
        if (c >= 'A' && c <= 'F') {
            return (char)(c - 'A' + 10);
        }

        // Carattere non valido
        return Character.MAX_VALUE;
    }
}

