public class MathUtils {
    /**
     * Calcola il fattoriale di $n$.
     * @param n il numero di input
     * @return il fattoriale
     */
    public static long factorial(int n) {
        if (n < 0) {
            throw new IllegalArgumentException("Input must be non-negative");
        }

        if (n == 0 || n == 1) {
            return 1;
        }

        long result = 1;
        for (int i = 2; i <= n; i++) {
            result *= i;
        }
        return result;
    }
}

import java.util.function.Predicate;

public class GraphTraversal {

    private class Node {
        // Node implementation details
    }

    private class OuterFaceCirculator {
        private Node current;
        private int direction;

        public OuterFaceCirculator(Node node, int dir) {
            this.current = node;
            this.direction = dir;
        }

        public Node getNode() {
            return current;
        }

        public void next() {
            // Move to next node based on direction
        }
    }

    /**
     * Trova e restituisce un 'circulator' al nodo sul confine del componente, che soddisfa il {@code predicate} oppure restituisce un 'circulator' al nodo {@code stop}.
     * @param predicate la condizione che il nodo desiderato deve soddisfare
     * @param start il nodo da cui iniziare la ricerca
     * @param stop il nodo con cui terminare la ricerca
     * @param dir la direzione da cui iniziare la traversata
     * @return un circolatore al nodo che soddisfa il {@code predicate} o al nodo {@code stop}
     */
    private OuterFaceCirculator selectOnOuterFace(Predicate<Node> predicate, Node start, Node stop, int dir) {
        OuterFaceCirculator circulator = new OuterFaceCirculator(start, dir);

        // Continue traversing until we find a node that satisfies the predicate or reach the stop node
        while (!predicate.test(circulator.getNode()) && circulator.getNode() != stop) {
            circulator.next();
        }

        return circulator;
    }
}

import org.apache.log4j.spi.LoggingEvent;
import java.util.ArrayList;
import java.util.List;

public class LogBuffer {
    private List<LoggingEvent> buffer;
    private static final int MAX_BUFFER_SIZE = 1000;

    public LogBuffer() {
        buffer = new ArrayList<>();
    }

    /**
     * Aggiunge un <code>evento</code> come ultimo evento nel buffer.
     */
    public void add(LoggingEvent event) {
        if (event == null) {
            return;
        }

        // Remove oldest event if buffer is full
        if (buffer.size() >= MAX_BUFFER_SIZE) {
            buffer.remove(0);
        }

        // Add new event to end of buffer
        buffer.add(event);
    }
}

public class LongComparator {
    /**
     * Confronta i due valori {@code long} specificati. Il segno del valore restituito è lo stesso di {@code ((Long) a).compareTo(b)}. 
     * <p> <b>Nota per Java 7 e versioni successive:</b> questo metodo dovrebbe essere considerato deprecato; utilizzare invece il metodo equivalente {@link Long#compare}.
     * @param a il primo {@code long} da confrontare
     * @param b il secondo {@code long} da confrontare
     * @return un valore negativo se {@code a} è minore di {@code b}; un valore positivo se {@code a} è maggiore di {@code b}; o zero se sono uguali
     */
    private static int compareSigned(long a, long b) {
        if (a < b) {
            return -1;
        }
        if (a > b) {
            return 1;
        }
        return 0;
    }
}

import java.util.Enumeration;

public class EnumerationUtils {

    /**
     * Copia l'Enumeration fornita in un array di Stringhe. L'Enumeration deve contenere solo elementi di tipo String.
     * @param enumeration l'Enumeration da copiare
     * @return l'array di Stringhe (<code>null</code> se l'Enumeration passata era <code>null</code>)
     */
    public static String[] toStringArray(Enumeration<String> enumeration) {
        if (enumeration == null) {
            return null;
        }

        // Count elements in enumeration
        int size = 0;
        Enumeration<String> counter = enumeration;
        while (counter.hasMoreElements()) {
            counter.nextElement();
            size++;
        }

        // Create array and copy elements
        String[] array = new String[size];
        int index = 0;
        while (enumeration.hasMoreElements()) {
            array[index++] = enumeration.nextElement();
        }

        return array;
    }
}

import java.util.Arrays;

public class ByteVector {
    private byte[] data;
    private int size;
    private static final int DEFAULT_CAPACITY = 10;

    public ByteVector() {
        data = new byte[DEFAULT_CAPACITY];
        size = 0;
    }

    public ByteVector putByteArray(final byte[] byteArrayValue, final int byteOffset, final int byteLength) {
        // Check if we need to resize the array
        ensureCapacity(size + byteLength);

        if (byteArrayValue != null) {
            // Validate offset and length
            if (byteOffset < 0 || byteLength < 0 || byteOffset + byteLength > byteArrayValue.length) {
                throw new IndexOutOfBoundsException("Invalid offset or length");
            }

            // Copy bytes from input array
            System.arraycopy(byteArrayValue, byteOffset, data, size, byteLength);
        } else {
            // Fill with null bytes if input array is null
            Arrays.fill(data, size, size + byteLength, (byte) 0);
        }

        size += byteLength;
        return this;
    }

    private void ensureCapacity(int minCapacity) {
        if (minCapacity > data.length) {
            int newCapacity = Math.max(data.length * 2, minCapacity);
            data = Arrays.copyOf(data, newCapacity);
        }
    }

    // Getter for current size
    public int size() {
        return size;
    }

    // Getter for underlying array
    public byte[] getData() {
        return Arrays.copyOf(data, size);
    }
}

