public class FileHandler {

    /**
     * Aggiungi i file specificati in ordine inverso.
     */
    private void addReverse(final InputStream[] files) {
        if (files == null || files.length == 0) {
            return;
        }

        List<InputStream> fileList = new ArrayList<>();

        // Add files to list
        for (InputStream file : files) {
            if (file != null) {
                fileList.add(file);
            }
        }

        // Reverse the list
        Collections.reverse(fileList);

        // Process files in reverse order
        for (InputStream file : fileList) {
            try {
                // Add file contents (implementation depends on specific requirements)
                processFile(file);
            } finally {
                try {
                    file.close();
                } catch (Exception e) {
                    // Handle close exception
                }
            }
        }
    }

    // Helper method to process individual files
    private void processFile(InputStream file) {
        // Implementation depends on specific requirements
        // Example: read file contents and add to collection/database etc.
    }
}

import java.util.Objects;

public class ShardingValidator {
    /**
     * @param modelName nome del modello dell'entità
     * @throws IllegalStateException se gli indici della chiave di sharding non sono continui
     */
    private void check(String modelName) throws IllegalStateException {
        if (Objects.isNull(modelName) || modelName.trim().isEmpty()) {
            throw new IllegalStateException("Model name cannot be null or empty");
        }

        // Verify sharding key indices are continuous
        int[] indices = getShardingKeyIndices(modelName);
        if (indices != null && indices.length > 0) {
            for (int i = 0; i < indices.length - 1; i++) {
                if (indices[i + 1] - indices[i] != 1) {
                    throw new IllegalStateException("Sharding key indices must be continuous for model: " + modelName);
                }
            }
        }
    }

    // Helper method to get sharding key indices
    private int[] getShardingKeyIndices(String modelName) {
        // Implementation would depend on how sharding keys are stored/retrieved
        // This is just a placeholder
        return new int[]{0, 1, 2};
    }
}

import java.io.IOException;
import java.io.InputStream;

public class ByteReader {
    private byte[] buffer;
    private int position;
    private int count;
    private InputStream input;
    private static final int BUFFER_SIZE = 8192;

    public ByteReader(InputStream input) {
        this.input = input;
        this.buffer = new byte[BUFFER_SIZE];
        this.position = 0;
        this.count = 0;
    }

    public byte readByte() throws IOException {
        if (position >= count) {
            count = input.read(buffer);
            if (count == -1) {
                throw new IOException("End of stream reached");
            }
            position = 0;
        }
        return buffer[position++];
    }
}

