import java.util.Set;
import java.util.HashSet;

public class Graph<V,E> {

    private Set<Edge<V,E>> edges;

    /**
     * Calcola la somma dei pesi che entrano in un vertice
     * @param v il vertice 
     * @return la somma dei pesi che entrano in un vertice
     */
    public double vertexWeight(Set<V> v) {
        double sum = 0.0;

        for(Edge<V,E> edge : edges) {
            if(v.contains(edge.getDestination())) {
                sum += edge.getWeight();
            }
        }

        return sum;
    }

    // Edge class to represent weighted edges
    private class Edge<V,E> {
        private V source;
        private V destination;
        private double weight;
        private E data;

        public Edge(V source, V destination, double weight, E data) {
            this.source = source;
            this.destination = destination;
            this.weight = weight;
            this.data = data;
        }

        public V getSource() {
            return source;
        }

        public V getDestination() {
            return destination;
        }

        public double getWeight() {
            return weight;
        }

        public E getData() {
            return data;
        }
    }
}

import java.util.Comparator;

public class ObjectComparator implements Comparator<Object> {

    /** 
     * @see Comparator 
     */
    public int compare(Object aObj1, Object aObj2) {
        if (aObj1 == null && aObj2 == null) {
            return 0;
        }
        if (aObj1 == null) {
            return -1; 
        }
        if (aObj2 == null) {
            return 1;
        }

        // Compare using toString() representation if objects are not null
        return aObj1.toString().compareTo(aObj2.toString());
    }
}

import java.util.ArrayList;
import java.util.List;
import org.apache.log4j.Appender;

public class Logger {
    private List<Appender> appenders;

    public Logger() {
        appenders = new ArrayList<>();
    }

    /**
     * Rimuove l'appender con il nome passato come parametro dalla lista degli appenders.
     */
    public void removeAppender(String name) {
        if (name == null) {
            return;
        }

        Appender toRemove = null;
        for (Appender appender : appenders) {
            if (name.equals(appender.getName())) {
                toRemove = appender;
                break;
            }
        }

        if (toRemove != null) {
            appenders.remove(toRemove);
            toRemove.close();
        }
    }
}

import org.apache.log4j.Appender;
import org.apache.log4j.LoggingEvent;
import org.apache.log4j.spi.AppenderAttachable;
import java.util.Enumeration;

public class Logger implements AppenderAttachable {

    private final Vector<Appender> appenders = new Vector<Appender>();

    /**
     * Chiama il metodo <code>doAppend</code> su tutti gli appender collegati.
     */
    public int appendLoopOnAppenders(LoggingEvent event) {
        int size = 0;

        if(appenders != null && !appenders.isEmpty()) {
            size = appenders.size();
            Enumeration<Appender> enumeration = appenders.elements();
            while(enumeration.hasMoreElements()) {
                Appender appender = enumeration.nextElement();
                appender.doAppend(event);
            }
        }

        return size;
    }
}

