import org.objectweb.asm.Symbol;
import org.objectweb.asm.Constants;

public class SymbolTable {
    private final Symbol[] symbols;
    private int size;

    public SymbolTable(int initialCapacity) {
        this.symbols = new Symbol[initialCapacity];
        this.size = 1;
    }

    int addConstantNameAndType(final String name, final String descriptor) {
        int hashCode = Symbol.CONSTANT_NAME_AND_TYPE_TAG + name.hashCode() * descriptor.hashCode();

        // Check if symbol already exists
        Symbol symbol = lookupSymbol(hashCode, Constants.CONSTANT_NAME_AND_TYPE, name, descriptor);
        if (symbol != null) {
            return symbol.index;
        }

        // Add name and descriptor to constant pool if not already present
        int nameIndex = addConstantUtf8(name);
        int descriptorIndex = addConstantUtf8(descriptor);

        // Create new NameAndType symbol
        symbol = new Symbol(
            size++, 
            Constants.CONSTANT_NAME_AND_TYPE,
            nameIndex,
            descriptorIndex,
            hashCode,
            symbols
        );

        // Add to symbol table
        int index = add(symbol);

        return index;
    }

    private Symbol lookupSymbol(int hashCode, int type, String name, String descriptor) {
        for (Symbol symbol : symbols) {
            if (symbol != null && 
                symbol.type == type && 
                symbol.hashCode == hashCode &&
                symbol.owner.equals(name) && 
                symbol.value.equals(descriptor)) {
                return symbol;    
            }
        }
        return null;
    }

    private int add(Symbol symbol) {
        if (size + 1 > symbols.length) {
            // Resize array if needed
            Symbol[] newSymbols = new Symbol[symbols.length * 2];
            System.arraycopy(symbols, 0, newSymbols, 0, symbols.length);
            symbols = newSymbols;
        }
        symbols[size - 1] = symbol;
        return size - 1;
    }

    private int addConstantUtf8(String value) {
        int hashCode = Symbol.CONSTANT_UTF8_TAG + value.hashCode();
        Symbol symbol = lookupSymbol(hashCode, Constants.CONSTANT_UTF8, value, null);
        if (symbol != null) {
            return symbol.index;
        }

        symbol = new Symbol(
            size++,
            Constants.CONSTANT_UTF8, 
            value,
            null,
            hashCode,
            symbols
        );

        return add(symbol);
    }
}

import java.util.regex.Pattern;
import java.util.regex.Matcher;

public class DotUtils {
    /**
     * Decomprime un identificatore di stringa DOT.
     * @param input l'input
     * @return l'output decompresso
     */
    private String unescapeId(String input) {
        if (input == null || input.isEmpty()) {
            return input;
        }

        // Remove quotes if present at start and end
        if (input.startsWith("\"") && input.endsWith("\"")) {
            input = input.substring(1, input.length() - 1);
        }

        // Replace escaped characters
        StringBuilder result = new StringBuilder();
        Pattern pattern = Pattern.compile("\\\\(.)");
        Matcher matcher = pattern.matcher(input);

        int lastEnd = 0;
        while (matcher.find()) {
            result.append(input.substring(lastEnd, matcher.start()));
            result.append(matcher.group(1));
            lastEnd = matcher.end();
        }
        result.append(input.substring(lastEnd));

        return result.toString();
    }
}

import java.util.ArrayList;
import java.util.List;

public class ArrayUtils {
    /**
     * Concatenare i dati degli array di Stringa forniti in uno solo, includendo gli elementi sovrapposti due volte.
     * L'ordine degli elementi negli array originali è preservato.
     * @param array1 il primo array (può essere <code>null</code>)
     * @param array2 il secondo array (può essere <code>null</code>) 
     * @return il nuovo array (<code>null</code> se entrambi gli array forniti erano <code>null</code>)
     */
    public static String[] concatenateStringArrays(String[] array1, String[] array2) {
        // If both arrays are null, return null
        if (array1 == null && array2 == null) {
            return null;
        }

        // If one array is null, return copy of the non-null array
        if (array1 == null) {
            return array2.clone();
        }
        if (array2 == null) {
            return array1.clone();
        }

        // Create list to store concatenated elements
        List<String> result = new ArrayList<>();

        // Add all elements from first array
        for (String s : array1) {
            if (s != null) {
                result.add(s);
            }
        }

        // Add all elements from second array
        for (String s : array2) {
            if (s != null) {
                result.add(s);
            }
        }

        // Convert list to array and return
        return result.toArray(new String[0]);
    }
}

import java.util.*;

public class BucketReloader {

    /**
     * Sposta tutti i vertici dal bucket con etichetta {@code minLabel} al bucket con etichetta 0. 
     * Pulisce il bucket con etichetta {@code minLabel}. Aggiorna le etichette di conseguenza.
     * @param bucketsByLabel i buckets in cui sono memorizzati i vertici
     * @param labels le etichette dei vertici 
     * @param minLabel il valore minimo del bucket non vuoto
     */
    private void reload(List<Set<Integer>> bucketsByLabel, List<Integer> labels, int minLabel) {
        Set<Integer> minBucket = bucketsByLabel.get(minLabel);
        Set<Integer> zeroBucket = bucketsByLabel.get(0);

        // Sposta tutti i vertici dal bucket minLabel al bucket 0
        for (Integer vertex : minBucket) {
            zeroBucket.add(vertex);
            labels.set(vertex, 0); // Aggiorna l'etichetta del vertice a 0
        }

        // Pulisce il bucket con etichetta minLabel
        minBucket.clear();
    }
}

public class ArrayUtils {
    /**
     * Aggiunge la Stringa fornita all'array di Stringhe dato, restituendo un nuovo array che consiste nei contenuti dell'array di input più la Stringa fornita.
     * @param array l'array a cui aggiungere (può essere <code>null</code>)
     * @param str la Stringa da aggiungere
     * @return il nuovo array (mai <code>null</code>)
     */
    public static String[] addStringToArray(String[] array, String str) {
        if (array == null) {
            return new String[] { str };
        }

        String[] newArray = new String[array.length + 1];
        System.arraycopy(array, 0, newArray, 0, array.length);
        newArray[array.length] = str;

        return newArray;
    }
}

public class StringUtils {
    /**
     * Restituisce il numero di occorrenze della sottostringa {@code sub} nella stringa {@code str}.
     * @param str stringa in cui cercare. Restituisce 0 se è null.
     * @param sub stringa da cercare. Restituisce 0 se è null.
     * @return il numero di occorrenze della sottostringa {@code sub} nella stringa {@code str}.
     */
    public static int countOccurrencesOf(String str, String sub) {
        if (str == null || sub == null || sub.length() == 0) {
            return 0;
        }

        int count = 0;
        int pos = 0;
        int idx;

        while ((idx = str.indexOf(sub, pos)) != -1) {
            count++;
            pos = idx + sub.length();
        }

        return count;
    }
}

