import java.util.ArrayList;
import java.util.List;
import javafx.util.Pair;

public class SuffixSumCalculator {

    /**
     * Calcola la somma dei suffissi di {@code bounds}. Restituisce la somma dei suffissi calcolata e la somma totale di tutti gli elementi nella lista {@code bounds}.
     * @param bounds lista di interi.
     * @return coppia calcolata di lista di somma suffisso e somma di tutti gli elementi.
     */
    private Pair<List<Integer>,Long> computeSuffixSum(List<Integer> bounds) {
        List<Integer> suffixSums = new ArrayList<>();
        long totalSum = 0;

        // Handle empty list case
        if (bounds == null || bounds.isEmpty()) {
            return new Pair<>(suffixSums, totalSum);
        }

        // Calculate total sum first
        for (int num : bounds) {
            totalSum += num;
        }

        // Calculate suffix sums
        int currentSum = 0;
        for (int i = bounds.size() - 1; i >= 0; i--) {
            currentSum += bounds.get(i);
            suffixSums.add(0, currentSum); // Add at beginning to maintain order
        }

        return new Pair<>(suffixSums, totalSum);
    }
}

import java.util.Arrays;

public class ArrayUtils {
    /**
     * Inverte l'ordine degli elementi nell'intervallo specificato all'interno dell'array fornito.
     * @param <V> il tipo di elementi nell'array
     * @param arr l'array
     * @param from l'indice del primo elemento (inclusivo) all'interno dell'intervallo da invertire
     * @param to l'indice dell'ultimo elemento (inclusivo) all'interno dell'intervallo da invertire
     */
    public static final <V> void reverse(V[] arr, int from, int to) {
        if (arr == null || arr.length == 0) {
            return;
        }

        if (from < 0 || to >= arr.length || from > to) {
            throw new IllegalArgumentException("Invalid range parameters");
        }

        while (from < to) {
            // Swap elements
            V temp = arr[from];
            arr[from] = arr[to];
            arr[to] = temp;

            from++;
            to--;
        }
    }
}

import java.util.Objects;

public class DoublyLinkedList<E> {
    private ListNode<E> head;
    private ListNode<E> tail;
    private int size;

    private static class ListNode<E> {
        E element;
        ListNode<E> next;
        ListNode<E> prev;

        ListNode(E element) {
            this.element = element;
        }
    }

    /**
     * Sposta in modo atomico tutti i {@link ListNode ListNodes} da {@code list} a questa lista 
     * come se ogni nodo fosse stato rimosso con {@link #removeListNode(ListNodeImpl)} da {@code list} 
     * e successivamente aggiunto a questa lista tramite {@link #addListNode(ListNodeImpl)}.
     */
    private void moveAllListNodes(DoublyLinkedList<E> list) {
        Objects.requireNonNull(list);

        if (list == this || list.size == 0) {
            return;
        }

        // If this list is empty, just take the other list's nodes
        if (size == 0) {
            this.head = list.head;
            this.tail = list.tail;
            this.size = list.size;
        } else {
            // Connect the tail of this list to the head of the other list
            this.tail.next = list.head;
            list.head.prev = this.tail;
            this.tail = list.tail;
            this.size += list.size;
        }

        // Clear the source list
        list.head = null;
        list.tail = null;
        list.size = 0;
    }
}

public class StringUtils {
    /**
     * <p>Controlla se una Stringa inizia con un prefisso specificato (opzionalmente senza distinzione tra maiuscole e minuscole).</p>
     * @see String#startsWith(String)
     * @param str  la Stringa da controllare, può essere null
     * @param prefix il prefisso da trovare, può essere null
     * @param ignoreCase indica se il confronto deve ignorare le maiuscole e minuscole (senza distinzione tra maiuscole e minuscole) o meno.
     * @return <code>true</code> se la Stringa inizia con il prefisso o entrambi <code>null</code>
     */
    private static boolean startsWith(final String str, final String prefix, final boolean ignoreCase) {
        if (str == null && prefix == null) {
            return true;
        }
        if (str == null || prefix == null) {
            return false;
        }
        if (prefix.length() > str.length()) {
            return false;
        }

        if (ignoreCase) {
            return str.regionMatches(true, 0, prefix, 0, prefix.length());
        } else {
            return str.startsWith(prefix);
        }
    }
}

