import javax.servlet.http.HttpServletRequest;
import org.atmosphere.cpr.AtmosphereResource;
import org.atmosphere.cpr.Meteor;

public class MeteorLookup {

    /**
     * Recupera un'istanza di {@link Meteor} basata su {@link HttpServletRequest}.
     * @param r {@link HttpServletRequest}
     * @return un {@link Meteor} o null se non trovato
     */
    public static Meteor lookup(HttpServletRequest r) {
        if (r == null) {
            return null;
        }

        try {
            // Try to get existing Meteor instance
            Meteor meteor = Meteor.build(r);
            if (meteor != null) {
                return meteor;
            }

            // Try to get from AtmosphereResource
            AtmosphereResource resource = (AtmosphereResource) r.getAttribute(AtmosphereResource.class.getName());
            if (resource != null) {
                return Meteor.build(resource);
            }
        } catch (Exception e) {
            // Return null if any errors occur during lookup
            return null;
        }

        return null;
    }
}

public class StringSplitter {
    /**
     * Divide una Stringa alla prima occorrenza del delimitatore. Non include il delimitatore nel risultato.
     * @param toSplit la stringa da dividere
     * @param delimiter il delimitatore con cui dividere la stringa
     * @return un array di due elementi con l'indice 0 che rappresenta la parte prima del delimitatore, e l'indice 1 che rappresenta la parte dopo il delimitatore (nessun elemento include il delimitatore); oppure <code>null</code> se il delimitatore non è stato trovato nella Stringa di input fornita
     */
    public static String[] split(String toSplit, String delimiter) {
        if (toSplit == null || delimiter == null) {
            return null;
        }

        int delimiterIndex = toSplit.indexOf(delimiter);

        if (delimiterIndex == -1) {
            return null;
        }

        String[] result = new String[2];
        result[0] = toSplit.substring(0, delimiterIndex);
        result[1] = toSplit.substring(delimiterIndex + delimiter.length());

        return result;
    }
}

import java.util.*;
import javafx.util.Pair;

public class SeparatorComputer {
    private Graph<V,E> graph; // Assuming a graph class with vertices V and edges E

    /**
     * Calcola la lista globale dei separatori del {@code grafo}. Più precisamente, per ogni arco $e$ in $G = (V, E)$ calcola la lista dei separatori minimi $S_e$ nel vicinato di $e$ e poi concatena queste liste. Nota: il risultato può contenere duplicati.
     * @return la lista dei separatori minimi di ogni arco $e$ nel grafo ispezionato
     */
    private List<Pair<List<Pair<Integer,Integer>>,E>> computeGlobalSeparatorList() {
        List<Pair<List<Pair<Integer,Integer>>,E>> globalSeparators = new ArrayList<>();

        // Iterate through all edges in the graph
        for (E edge : graph.edges()) {
            List<Pair<Integer,Integer>> separators = new ArrayList<>();

            // Get vertices incident to the edge
            V source = graph.getEdgeSource(edge);
            V target = graph.getEdgeTarget(edge);

            // Get neighborhood of both vertices
            Set<V> sourceNeighbors = new HashSet<>(graph.neighborsOf(source));
            Set<V> targetNeighbors = new HashSet<>(graph.neighborsOf(target));

            // Find common neighbors that form minimal separators
            Set<V> commonNeighbors = new HashSet<>(sourceNeighbors);
            commonNeighbors.retainAll(targetNeighbors);

            // Create pairs of vertices that form minimal separators
            for (V v1 : commonNeighbors) {
                for (V v2 : commonNeighbors) {
                    if (!v1.equals(v2)) {
                        // Assuming vertices have integer IDs
                        Pair<Integer,Integer> separator = new Pair<>(
                            ((Integer)v1.getId()),
                            ((Integer)v2.getId())
                        );
                        separators.add(separator);
                    }
                }
            }

            // Add the separators list along with the edge to global list
            globalSeparators.add(new Pair<>(separators, edge));
        }

        return globalSeparators;
    }
}

public class ArrayUtils {
