import javax.swing.*;
import java.awt.*;

public class TableUtils {

    /**
     * Seleziona la riga specificata nella JTable specificata e scorre lo JScrollPane specificato fino alla riga appena selezionata. 
     * Più importante, la chiamata a repaint() è ritardata abbastanza a lungo da permettere alla tabella di dipingere correttamente 
     * la riga appena selezionata, che potrebbe essere fuori dallo schermo.
     * @param table deve appartenere allo JScrollPane specificato
     */
    public static void selectRow(int row, JTable table, JScrollPane pane) {
        if (row < 0 || row >= table.getRowCount()) {
            return;
        }

        // Seleziona la riga
        table.setRowSelectionInterval(row, row);

        // Calcola il rettangolo della riga selezionata
        Rectangle rect = table.getCellRect(row, 0, true);

        // Scorre fino alla riga selezionata
        table.scrollRectToVisible(rect);

        // Ritarda il repaint per assicurare che la selezione sia visibile
        SwingUtilities.invokeLater(new Runnable() {
            @Override
            public void run() {
                // Forza lo scroll
                pane.getViewport().scrollRectToVisible(rect);

                // Ritarda ulteriormente il repaint
                SwingUtilities.invokeLater(new Runnable() {
                    @Override
                    public void run() {
                        table.repaint();
                    }
                });
            }
        });
    }
}

import java.util.Arrays;

public class ByteVector {
    private byte[] bytes;
    private int size;
    private static final int INT_SIZE = 4;

    public ByteVector() {
        bytes = new byte[10];
        size = 0;
    }

    public ByteVector putInt(final int intValue) {
        ensureCapacity(size + INT_SIZE);

        // Store int value in big-endian format
        bytes[size] = (byte) ((intValue >> 24) & 0xFF);
        bytes[size + 1] = (byte) ((intValue >> 16) & 0xFF); 
        bytes[size + 2] = (byte) ((intValue >> 8) & 0xFF);
        bytes[size + 3] = (byte) (intValue & 0xFF);

        size += INT_SIZE;
        return this;
    }

    private void ensureCapacity(int minCapacity) {
        if (minCapacity > bytes.length) {
            int newCapacity = Math.max(bytes.length * 2, minCapacity);
            bytes = Arrays.copyOf(bytes, newCapacity);
        }
    }
}

public class ArrayUtils {
    /**
     * Confronta i <code>count</code> primi byte negli array <code>a</code> e <code>b</code>.
     * @param a     Il primo array da confrontare.
     * @param b     Il secondo array da confrontare. 
     * @param count Quanti byte devono essere confrontati.
     * @return <code>true</code> se i <code>count</code> primi byte negli array <code>a</code> e <code>b</code> sono uguali.
     */
    public static boolean arrayequals(byte[] a, byte[] b, int count) {
        if (a == null || b == null) {
            return false;
        }

        if (a.length < count || b.length < count) {
            return false;
        }

        for (int i = 0; i < count; i++) {
            if (a[i] != b[i]) {
                return false;
            }
        }

        return true;
    }
}

import java.lang.StringBuffer;

public class NameAbbreviator {
    /**
     * Abbrevia il nome.
     * @param buf buffer a cui aggiungere l'abbreviazione.
     * @param nameStart inizio del nome da abbreviare.
     */
    public void abbreviate(final int nameStart, final StringBuffer buf) {
        if (buf == null || nameStart < 0 || nameStart >= buf.length()) {
            return;
        }

        // Get the first character
        char firstChar = buf.charAt(nameStart);

        // Find the end of the name (next space or end of buffer)
        int nameEnd = nameStart;
        while (nameEnd < buf.length() && !Character.isWhitespace(buf.charAt(nameEnd))) {
            nameEnd++;
        }

        // Delete everything after first character up to end of name
        if (nameEnd > nameStart + 1) {
            buf.delete(nameStart + 1, nameEnd);

            // Add period after abbreviated character
            buf.insert(nameStart + 1, '.');
        }
    }
}

import java.lang.reflect.Type;
import java.lang.reflect.TypeVariable;
import java.lang.reflect.WildcardType;
import java.lang.reflect.ParameterizedType;

public class TypeResolver {

    /**
     * Risolve il primo vincolo per il {@code typeVariable}, restituendo {@code Unknown.class} se non può essere risolto.
     */
    public static Type resolveBound(TypeVariable<?> typeVariable) {
        Type[] bounds = typeVariable.getBounds();

        if (bounds == null || bounds.length == 0) {
            return Unknown.class;
        }

        Type bound = bounds[0];

        if (bound instanceof TypeVariable) {
            return resolveBound((TypeVariable<?>) bound);
        }

        if (bound instanceof WildcardType) {
            Type[] upperBounds = ((WildcardType) bound).getUpperBounds();
            if (upperBounds != null && upperBounds.length > 0) {
                return upperBounds[0];
            }
            return Unknown.class;
        }

        if (bound instanceof ParameterizedType) {
            return ((ParameterizedType) bound).getRawType();
        }

        return bound;
    }

    private static class Unknown {
        // Marker class for unresolvable bounds
    }
}

import org.jgrapht.Graph;
import java.util.Set;

public class GraphUtils {
    /**
     * Controlla se il sottografo di <code>graph</code> indotto dai dati <code>vertices</code> è completo, cioè un clique.
     * @param graph il grafo.
     * @param vertices i vertici da cui indurre il sottografo.
     * @return true se il sottografo indotto è un clique.
     */
    private static <V,E> boolean isClique(Graph<V,E> graph, Set<V> vertices) {
        // Per ogni coppia di vertici nel set
        for (V v1 : vertices) {
            for (V v2 : vertices) {
                // Salta il confronto di un vertice con se stesso
                if (v1.equals(v2)) {
                    continue;
                }
                // Se non esiste un arco tra i due vertici, non è un clique
                if (!graph.containsEdge(v1, v2)) {
                    return false;
                }
            }
        }
        // Se arriviamo qui, tutti i vertici sono collegati tra loro
        return true;
    }
}

import java.util.*;

public class BoundCalculator<K extends Comparable<K>> {

    /**
     * Trova un limite inferiore massimo per ogni chiave.
     * @param keys lista delle chiavi.
     * @return i limiti inferiori delle chiavi calcolati.
     */
    private List<Integer> computeLowerBounds(List<K> keys) {
        if (keys == null || keys.isEmpty()) {
            return new ArrayList<>();
        }

        List<Integer> lowerBounds = new ArrayList<>(keys.size());

        for (int i = 0; i < keys.size(); i++) {
            K currentKey = keys.get(i);
            int maxLowerBound = 0;

            for (int j = 0; j < i; j++) {
                K previousKey = keys.get(j);
                if (previousKey.compareTo(currentKey) <= 0) {
                    maxLowerBound = Math.max(maxLowerBound, lowerBounds.get(j) + 1);
                }
            }

            lowerBounds.add(maxLowerBound);
        }

        return lowerBounds;
    }
}

import java.util.Stack;

public class FrameHandler {
    private Stack<String> outputStack;

    public FrameHandler() {
        this.outputStack = new Stack<>();
    }

    /**
     * Rimuove quanti più tipi astratti possibile dallo stack del frame di output come descritto dal descrittore fornito.
     * @param descriptor un tipo o un descrittore di metodo (nel qual caso vengono rimossi i suoi tipi di argomento).
     */
    private void pop(final String descriptor) {
        if (descriptor == null || descriptor.isEmpty()) {
            return;
        }

        int index = 0;
        while (index < descriptor.length()) {
            char c = descriptor.charAt(index);

            switch (c) {
                case '(':
                    // Skip opening parenthesis for method descriptor
                    index++;
                    continue;
                case ')':
                    // Stop at closing parenthesis
                    return;
                case 'B':
                case 'C':
                case 'D':
                case 'F':
                case 'I':
                case 'J':
                case 'S':
                case 'Z':
                    // Pop primitive types
                    if (!outputStack.isEmpty()) {
                        outputStack.pop();
                    }
                    if (c == 'D' || c == 'J') {
                        // Double and Long take two stack slots
                        if (!outputStack.isEmpty()) {
                            outputStack.pop();
                        }
                    }
                    index++;
                    break;
                case 'L':
                    // Pop object reference type
                    if (!outputStack.isEmpty()) {
                        outputStack.pop();
                    }
                    // Skip to semicolon
                    index = descriptor.indexOf(';', index) + 1;
                    break;
                case '[':
                    // Skip array dimension
                    index++;
                    break;
                default:
                    index++;
                    break;
            }
        }
    }
}

package org.apache.commons.lang3;

public class CharUtils {
    /**
     * <p>Controlla se il carattere è ASCII a 7 bit.</p>
     * <pre>
     * CharUtils.isAscii('a')  = true
     * CharUtils.isAscii('A')  = true
     * CharUtils.isAscii('3')  = true
     * CharUtils.isAscii('-')  = true
     * CharUtils.isAscii('\n') = true
     * CharUtils.isAscii('&copy;') = false
     * </pre>
     * @param ch il carattere da controllare
     * @return true se inferiore a 128
     */
    public static boolean isAscii(final char ch) {
        return ch < 128;
    }
}

import java.util.*;

public class BoundCalculator<K extends Comparable<K>> {

    /**
     * Trova un limite superiore minimo per ogni chiave.
     * @param keys una lista di chiavi.
     * @return il limite superiore delle chiavi calcolato.
     */
    private List<Integer> computeUpperBounds(List<K> keys) {
        if (keys == null || keys.isEmpty()) {
            return new ArrayList<>();
        }

        List<Integer> upperBounds = new ArrayList<>(keys.size());

        // Per ogni chiave, trova il suo limite superiore
        for (int i = 0; i < keys.size(); i++) {
            K currentKey = keys.get(i);
            int upperBound = i;

            // Confronta con tutte le chiavi successive
            for (int j = i + 1; j < keys.size(); j++) {
                if (currentKey.compareTo(keys.get(j)) <= 0) {
                    upperBound = j;
                }
            }

            upperBounds.add(upperBound);
        }

        return upperBounds;
    }
}

public class TemplateEncoder {
    /**
     * Codifica una stringa con nomi di parametri di template presenti, in particolare i caratteri '{' e '}' verranno codificati in percentuale.
     * @param s la stringa con zero o più nomi di parametri di template
     * @return la stringa con i nomi di parametri di template codificati.
     */
    public static String encodeTemplateNames(String s) {
        if (s == null || s.isEmpty()) {
            return s;
        }

        StringBuilder result = new StringBuilder();

        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);

            if (c == '{') {
                result.append("%7B");
            } else if (c == '}') {
                result.append("%7D");
            } else {
                result.append(c);
            }
        }

        return result.toString();
    }
}

import java.awt.geom.Point2D;

public class PointUtils {
    /**
     * Confronta due punti per uguaglianza utilizzando una tolleranza di 1e-9.
     * @param p1 il primo punto
     * @param p2 il secondo punto
     * @return se i due punti sono uguali o meno
     */
    public static boolean equals(Point2D p1, Point2D p2) {
        if (p1 == null || p2 == null) {
            return false;
        }

        double tolerance = 1e-9;

        return Math.abs(p1.getX() - p2.getX()) < tolerance && 
               Math.abs(p1.getY() - p2.getY()) < tolerance;
    }
}

