import java.io.File;
import java.nio.file.Path;
import java.nio.file.Paths;

public class PathUtils {

    /**
     * Applica il percorso relativo fornito al percorso dato, assumendo la separazione standard delle cartelle Java (cioè i separatori "/").
     * @param path il percorso da cui partire (di solito un percorso di file completo)
     * @param relativePath il percorso relativo da applicare (rispetto al percorso di file completo sopra)
     * @return il percorso di file completo che risulta dall'applicazione del percorso relativo
     */
    public static String applyRelativePath(String path, String relativePath) {
        // Normalizza i separatori di percorso
        path = path.replace('\\', '/');
        relativePath = relativePath.replace('\\', '/');

        // Rimuovi eventuali separatori finali
        if (path.endsWith("/")) {
            path = path.substring(0, path.length() - 1);
        }

        // Gestisci il caso in cui il percorso relativo inizia con "/"
        if (relativePath.startsWith("/")) {
            relativePath = relativePath.substring(1);
        }

        // Usa Path per risolvere il percorso relativo
        Path basePath = Paths.get(path);
        Path resolvedPath = basePath.resolve(relativePath).normalize();

        // Converti il risultato in una stringa con separatori forward slash
        return resolvedPath.toString().replace('\\', '/');
    }
}

package org.apache.commons.lang3;

public class StringUtils {
    /**
     * Trova il primo indice all'interno di una Stringa, gestendo <code>null</code>.
     * Questo metodo utilizza {@link String#indexOf(String)}.
     *
     * @param str la Stringa da controllare, può essere null
     * @param searchStr la Stringa da trovare, può essere null
     * @return l'indice della prima occorrenza, -1 se non trovato o se str è null
     */
    public static int indexOf(String str, String searchStr) {
        if (str == null || searchStr == null) {
            return -1;
        }
        return str.indexOf(searchStr);
    }
}

import java.util.ArrayList;
import java.util.List;

public class ArrayUtils {
    /**
     * Restituisce un nuovo array di Stringhe senza elementi null. Metodo interno utilizzato per normalizzare le liste di esclusione (array e collezioni). Si noti che {@link Arrays#sort(Object[])} genererà un {@link NullPointerException} se un elemento dell'array è <code>null</code>.
     * @param array L'array da controllare
     * @return L'array fornito o un nuovo array senza null.
     */
    static String[] toNoNullStringArray(Object[] array) {
        if (array == null) {
            return new String[0];
        }

        List<String> result = new ArrayList<>();
        for (Object obj : array) {
            if (obj != null) {
                result.add(obj.toString());
            }
        }

        return result.toArray(new String[0]);
    }
}

import java.io.File;

public class FilenameUtils {

    private static final char EXTENSION_SEPARATOR = '.';
    private static final char UNIX_SEPARATOR = '/';
    private static final char WINDOWS_SEPARATOR = '\\';

    /**
     * Restituisce l'indice dell'ultimo carattere separatore dell'estensione, che è un punto.
     * <p>
     * Questo metodo verifica anche che non ci sia un separatore di directory dopo l'ultimo punto.
     * Per fare ciò, utilizza {@link #indexOfLastSeparator(String)} che gestirà un file sia in formato Unix che Windows.
     * <p>
     * L'output sarà lo stesso indipendentemente dalla macchina su cui il codice viene eseguito.
     *
     * @param filename il nome del file in cui trovare l'ultimo separatore di percorso, null restituisce -1
     * @return l'indice dell'ultimo carattere separatore, o -1 se non esiste tale carattere
     */
    public static int indexOfExtension(String filename) {
        if (filename == null) {
            return -1;
        }

        int extensionPos = filename.lastIndexOf(EXTENSION_SEPARATOR);
        int lastSeparator = indexOfLastSeparator(filename);

        // Se non c'è un punto o se l'ultimo separatore è dopo l'ultimo punto
        if (extensionPos == -1 || lastSeparator > extensionPos) {
            return -1;
        }
        return extensionPos;
    }

    /**
     * Metodo di supporto per trovare l'ultimo separatore di directory
     */
    private static int indexOfLastSeparator(String filename) {
        if (filename == null) {
            return -1;
        }
        int lastUnixPos = filename.lastIndexOf(UNIX_SEPARATOR);
        int lastWindowsPos = filename.lastIndexOf(WINDOWS_SEPARATOR);
        return Math.max(lastUnixPos, lastWindowsPos);
    }
}

public class CacheMetrics {
    /**
     * @param timestamp        tempo attuale
     * @param expiredThreshold rappresenta la durata tra l'ultimo aggiornamento e il momento in cui si rimuove dalla cache.
     * @return true significa che queste metriche devono essere rimosse dalla cache.
     */
    public boolean isExpired(long timestamp, long expiredThreshold) {
        long lastUpdateTime = System.currentTimeMillis(); // Get current time in milliseconds
        long timeDifference = timestamp - lastUpdateTime;

        return timeDifference >= expiredThreshold;
    }
}

import java.util.*;

public class Graph {
    private List<Node> nodes;
    private List<Edge> edges;
    private int currentNodeIndex;

    // Constructor and other methods...

    /**
     * Restituisce un arco che collega il nodo precedentemente restituito con il nodo che verrà restituito successivamente. 
     * Se uno dei nodi menzionati è virtuale, l'arco sarà incidente al suo corrispondente reale.
     * @return un arco dal nodo corrente al nodo successivo
     */
    public Edge edgeToNext() {
        if (nodes == null || nodes.isEmpty() || currentNodeIndex >= nodes.size() - 1) {
            return null;
        }

        Node currentNode = nodes.get(currentNodeIndex);
        Node nextNode = nodes.get(currentNodeIndex + 1);

        // Get real nodes if virtual
        Node realCurrentNode = currentNode.isVirtual() ? currentNode.getRealNode() : currentNode;
        Node realNextNode = nextNode.isVirtual() ? nextNode.getRealNode() : nextNode;

        // Find edge between real nodes
        for (Edge edge : edges) {
            if ((edge.getSource().equals(realCurrentNode) && edge.getDestination().equals(realNextNode)) ||
                (edge.getSource().equals(realNextNode) && edge.getDestination().equals(realCurrentNode))) {
                return edge;
            }
        }

        return null;
    }
}

class Node {
    private boolean isVirtual;
    private Node realNode;

    public boolean isVirtual() {
        return isVirtual;
