}

public class StringMatcher {
    /**
     * Restituisce {@code true} se la stringa fornita corrisponde alla sottostringa fornita all'indice specificato, {@code false} altrimenti.
     * @param str la stringa originale (o StringBuilder)
     * @param index l'indice nella stringa originale da cui iniziare a confrontare
     * @param substring la sottostringa da confrontare all'indice specificato
     * @return {@code true} se la stringa fornita corrisponde alla sottostringa fornita all'indice specificato, {@code false} altrimenti.
     */
    public static boolean substringMatch(CharSequence str, int index, CharSequence substring) {
        // Check for null inputs
        if (str == null || substring == null) {
            return false;
        }

        // Check if index is out of bounds
        if (index < 0 || index > str.length()) {
            return false;
        }

        // Check if substring is longer than remaining characters from index
        if (str.length() - index < substring.length()) {
            return false;
        }

        // Compare each character
        for (int i = 0; i < substring.length(); i++) {
            if (str.charAt(index + i) != substring.charAt(i)) {
                return false;
            }
        }

        return true;
    }
}

import org.apache.log4j.AppenderSkeleton;
import org.apache.log4j.Layout;
import org.apache.log4j.spi.LoggingEvent;
import java.io.IOException;
import java.io.PrintWriter;
import java.net.Socket;
import java.util.ArrayList;
import java.util.List;

public class SocketAppender extends AppenderSkeleton {

    private List<Socket> connectedClients;
    private List<PrintWriter> clientWriters;

    public SocketAppender() {
        connectedClients = new ArrayList<>();
        clientWriters = new ArrayList<>();
    }

    @Override
    protected void append(LoggingEvent event) {
        if (event == null) return;

        String formattedMessage = this.layout.format(event);

        // Iterate through all connected clients and send the log message
        for (int i = 0; i < clientWriters.size(); i++) {
            try {
                PrintWriter writer = clientWriters.get(i);
                writer.println(formattedMessage);
                writer.flush();
            } catch (Exception e) {
                // If there's an error writing to a client, remove it
                removeClient(i);
                i--; // Adjust index since we removed an element
            }
        }
    }

    public void addClient(Socket clientSocket) throws IOException {
        connectedClients.add(clientSocket);
        clientWriters.add(new PrintWriter(clientSocket.getOutputStream(), true));
    }

    private void removeClient(int index) {
        try {
            connectedClients.get(index).close();
        } catch (IOException e) {
            // Ignore close errors
        }
        connectedClients.remove(index);
        clientWriters.remove(index);
    }

    @Override
    public void close() {
        for (Socket socket : connectedClients) {
            try {
                socket.close();
            } catch (IOException e) {
                // Ignore close errors
            }
        }
        connectedClients.clear();
        clientWriters.clear();
    }

    @Override
    public boolean requiresLayout() {
        return true;
    }
}

package org.apache.commons.lang3;

/**
 * Utility class for character operations.
 */
public class CharUtils {

    /**
     * Array cache of commonly used characters converted to String.
     * We cache the first 128 ASCII characters since they're most common.
     */
    private static final String[] CHAR_STRING_CACHE = new String[128];

    // Initialize the cache
    static {
        for (int i = 0; i < CHAR_STRING_CACHE.length; i++) {
            CHAR_STRING_CACHE[i] = String.valueOf((char) i);
        }
    }

    /** 
     * <p>Converte il carattere in una Stringa che contiene il singolo carattere.</p> 
     * <p>Per i caratteri ASCII a 7 bit, utilizza una cache che restituirà lo stesso oggetto String ogni volta.</p> 
     * <pre>
     * CharUtils.toString(' ')  = " "
     * CharUtils.toString('A')  = "A"
     * </pre>
     * @param ch  il carattere da convertire
     * @return una Stringa contenente il carattere specificato
     */
    public static String toString(final char ch) {
        if (ch < CHAR_STRING_CACHE.length) {
            return CHAR_STRING_CACHE[ch];
        }
        return String.valueOf(ch);
    }
}

import java.io.IOException;

public class FieldReader {
    private boolean isCompressed;
    private int compressedLength;
    private int currentPosition;
    private byte[] buffer;

    /**
     * Controlla se questo campo è stato compresso in un campo delimitato da lunghezza. 
     * In tal caso, aggiorna lo stato interno per riflettere che i campi compressi stanno per essere letti.
     * @throws IOException
     */
    private void checkIfPackedField() throws IOException {
        if (currentPosition < buffer.length - 4) {
            // Check for compression marker bytes
            if (buffer[currentPosition] == 0x1F && buffer[currentPosition + 1] == 0x8B) {
                // Get compressed length from next 4 bytes
                compressedLength = ((buffer[currentPosition + 2] & 0xFF) << 24) |
                                 ((buffer[currentPosition + 3] & 0xFF) << 16) |
                                 ((buffer[currentPosition + 4] & 0xFF) << 8) |
                                 (buffer[currentPosition + 5] & 0xFF);

                isCompressed = true;
                currentPosition += 6; // Skip marker and length bytes
            } else {
                isCompressed = false;
            }
        } else {
            throw new IOException("Buffer overflow while checking for packed field");
        }
    }
}

import java.io.IOException;
import java.io.InputStream;

public class CodedInputStream {
    private final InputStream input;
    private int lastTag = 0;
    private int pos = 0;
    private byte[] buffer;
    private int bufferSize;
    private static final int BUFFER_SIZE = 4096;

    public CodedInputStream(InputStream input) {
        this.input = input;
        this.buffer = new byte[BUFFER_SIZE];
        this.bufferSize = 0;
    }

    public int readTag() throws IOException {
        if (isAtEnd()) {
            lastTag = 0;
            return 0;
        }

        lastTag = readRawVarint32();
        if (lastTag == 0) {
            // If we actually read zero, that's not a valid tag.
            throw new IOException("Invalid tag: zero is not a valid tag value");
        }
        return lastTag;
    }

    private boolean isAtEnd() throws IOException {
        if (pos < bufferSize) {
            return false;
        }

        int read = input.read(buffer, 0, BUFFER_SIZE);
        if (read <= 0) {
            return true;
        }

        pos = 0;
        bufferSize = read;
        return false;
    }

    private int readRawVarint32() throws IOException {
        int result = 0;
        int shift = 0;

        while (shift < 32) {
            byte b = readRawByte();
            result |= (b & 0x7F) << shift;
            if ((b & 0x80) == 0) {
                return result;
            }
            shift += 7;
        }
        throw new IOException("Malformed varint32");
    }

    private byte readRawByte() throws IOException {
        if (pos == bufferSize) {
            int read = input.read(buffer, 0, BUFFER_SIZE);
            if (read <= 0) {
                throw new IOException("End of stream reached");
            }
            pos = 0;
            bufferSize = read;
        }
        return buffer[pos++];
    }
}

import java.util.Arrays;

public class ByteVector {
    private byte[] data;
    private int size;
    private static final int DEFAULT_CAPACITY = 10;

    public ByteVector() {
        data = new byte[DEFAULT_CAPACITY];
        size = 0;
    }

    /**
     * Inserisce due byte in questo vettore di byte. Il vettore di byte viene automaticamente ingrandito se necessario.
     * @param byteValue1 un byte.
     * @param byteValue2 un altro byte.
     * @return questo vettore di byte.
     */
    final ByteVector put11(final int byteValue1, final int byteValue2) {
        if (size + 2 > data.length) {
            // Double array size if more space needed
            data = Arrays.copyOf(data, data.length * 2);
        }

        data[size++] = (byte) byteValue1;
        data[size++] = (byte) byteValue2;

        return this;
    }
}

